    // .............
    // #1: Start2

    void passage1_Init()
    {
        this.Passages[@"Start2"] = new StoryPassage(@"Start2", new string[] { "Trad-FR", }, passage1_Main);
    }

    IStoryThread passage1_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("LE SECRET DE MON PÈRE");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
        }
        yield return text("Choisissez un Scénario pour ");
        yield return text(Vars.playtxt);
        yield return text(" ");
        yield return text("joueurs :");
        //yield return text("\'\'");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Temps de Guerre", "Scenario2", null);
        yield return lineBreak();
        yield return link("L\'Industrie Éternelle", "Scenario3", null);
        yield return lineBreak();
        yield return link("La Peur de l\'Inconnu", "ScenarioBox-FOTU", null);
        yield return lineBreak();
        yield return link("Le Fardeau de la Maladie", "Scenario5Start", null);
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Pour une explication du fonctionnement de ce livret Histoire,");
        }
        yield return text(" ");
        yield return link("cliquez ici.", "StoryBook", null);
        yield return lineBreak();
        Vars.tracker = 0;
        yield break;
    }


    // .............
    // #2: FearoftheUnknownStart

    void passage2_Init()
    {
        this.Passages[@"FearoftheUnknownStart"] = new StoryPassage(@"FearoftheUnknownStart", new string[] { "INTRO", "revised", "rev2", "Trad-FR", }, passage2_Main);
    }

    IStoryThread passage2_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION I : La Peur de l\'Inconnu");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre expédiée par ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("14 juillet 1831.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Après réflexion, je vous rapporte avec réticence un événement boulversant auquel " +
            "j\'ai assisté à mon arrivée. J\'espère ainsi apaiser le tourment que m\'imposent ce" +
            "s images atroces si profondément ancrées dans mon esprit.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Je vous épargnerai les détails de mon voyage jusqu'à cette ville lugubre où je dois régler la succession de mon père décédé. Mais en arrivant dans ses faubourgs, ma moitié attira mon attention sur un groupe d'hommes et de femmes courant en direction du centre-ville pour rejoindre une foule nombreuse et agitée. Intrigué par ce rassemblement, je décidai d'assouvir ma curiosité en frappant du poing le toit de la voiture pour demander au cocher de s'approcher des festivités. ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Il fit la sourde oreille et continua malgré mon insistance, alors que je répétais mon ordre à trois reprises. Frustré, je sortis la tête par la fenêtre afin de lui exprimer mon mécontentement plus directement. C'est ainsi que je découvris la source macabre de son avisée obstination. J'aperçus un bref instant - toutefois bien assez long pour que cette image reste à jamais gravée dans mon esprit - la raison d'une telle agitation : la foule entourait une grande estrade en bois sur laquelle était pendu, au bout d'une épaisse corde en chanvre, le cadavre d'une jeune femme. Je croisai son regard livide juste avant qu'elle ne disparaisse de ma vue, derrière les maisons.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Une peur irrationnelle s'était emparée de la population. Je te l'assure ! La région est percluse de superstitions fantaisistes qui ne sont pas compatibles avec la morale rigide de l'Église. Dès que la moindre personne de cette communauté soudée sort d'une de ses maisons aux volets fermés, elle me regarde comme une bête de foire. Leur attitude me rend chaque excursion en ville insupportable. Les accusations de sorcellerie se répandent comme une traînée de poudre, et la paranoïa semble paralyser leurs esprits.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cet isolement subi se révèlera peut-être bénéfique pour mes recherches, car malgré l'agitation ambiante, je parviens à me concentrer comme jamais auparavant. J'ai découvert récemment le vieux journal de mon père. Bien qu'il paraisse quelque peu banal, il provoque une étrange attirance en moi. Peut-être de nouvelles pistes pour mes recherches. J'espère qu'il me changera un peu les idées en ces temps troublés.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Continuer...", "ManiaSpecial", null);
        yield return lineBreak();
        Vars.newspaper = macros1.either("Le Courrier de " + Vars.townname, "La Gazette de " + Vars.townname, "La Vie à " + Vars.townname, "Les Échos de " + Vars.townname, "Enquêtes à " + Vars.townname);
        Vars.whpg = 0;
        Vars.fp10PV = 0;
        Vars.fpresearch2 = 0;
        Vars.fpsanity3 = 0;
        Vars.fpcreepy3 = 0;
        Vars.gen3pg = 0;
        Vars.plA = 0;
        Vars.plB = 0;
        Vars.plC = 0;
        Vars.plD = 0;
        Vars.plE = 0;
        Vars.onecount = 0;
        yield return lineBreak();
        yield break;
    }


