    IStoryThread passage6_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Une exécution publique ?");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal de ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("16 septembre 1850, Roumanie.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Il est pratiquement minuit et j'ai du mal à trouver mes mots. Je n'arrive pas moi-même à comprendre ce que je ressens : euphorie ou culpabilité ? Tandis que la foule apeurée contemplait la danse des flammes dans la nuit, moi, au beau milieu de tout cela, je restais, l'esprit subjugué par autant de sauvagerie. Je n'aurais jamais pensé que la paranoïa puisse engendrer une telle cruauté !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Tout commença lors d\'un souper en famille : un cortège passa devant nos fenêtres," +
            " emportant le ");
        using (styleScope("bold", true))
        {
            yield return text("forgeron");
        }
        yield return text(" ");
        yield return text("- accusé de sorcellerie - jusqu\'aux marches de l\'Hôtel de Ville. Il pleurait et h" +
            "urlait son innocence. Lorsque ses mains furent détachées, il accusa immédiatemen" +
            "t Henriette, la ");
        using (styleScope("bold", true))
        {
            yield return text("bouchère");
        }
        yield return text(" ");
        yield return text("de la ville, de le manipuler. Aussitôt, il se mit à convulser violemment et à ges" +
            "ticuler comme s\'il était en transe, alors qu\'elle tentait désespérément de repou" +
            "sser ses accusations.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Lorsque nous nous approchâmes pour tenter d\'en savoir plus quant à l\'agitation qu" +
            "i nous avait privé de dessert, je crus voir dans les yeux du ");
        using (styleScope("bold", true))
        {
            yield return text("forgeron");
        }
        yield return text(" ");
        yield return text("le feu d\'une ardente détermination. Il était prêt à nous offrir n\'importe quoi po" +
            "ur que l\'on épargne sa vie.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("La ");
        using (styleScope("bold", true))
        {
            yield return text("bouchère");
        }
        yield return text(" ");
        yield return text("fut amenée à son tour sur les marches de l\'Hôtel de Ville, silencieuse, désespéré" +
            "e, presque résignée. Nous savions qu\'Henriette nous proposerait le même arrangem" +
            "ent.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Il n\'y avait aucun moyen d\'épancher la soif de catharsis de cette foule sans lui " +
            "offrir une effusion de sang. Cette nuit, une sorcière fut brûlée.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.players == 2)
        {
            yield return link("Cliquez pour continuer...", "2PS4Kill2", null);
        }
        else
        {
            yield return link("Cliquez pour continuer...", "S4Kill2", null);
        }
        yield return lineBreak();
        yield break;
    }


