            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("Avril 1863. Roumanie.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"J'espère que vous pardonnerez ma manière cavalière de vous faire parvenir cette lettre. Suite aux récents événements, je n'ai plus aucune confiance en les services postaux et je préfère mandater un messager privé. Ce message vous est uniquement destiné et il m'est insupportable d'imaginer que ceux qui complotent de manière si flagrante à mon encontre puissent en découvrir le contenu ! ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cette ville est devenue complètement folle.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Nous ne sommes installés que depuis quelques mois en famille avec mes plus fidèles domestiques, je m'habitue à peine aux toits de chaume et à ces paysages bucoliques, et j'ai pourtant déjà vu des feux illuminer la nuit, entendu les cris des damnés et le grincement des corps qui se balancent sous la potence. La foule s'abat au soir, torches à la main, sur ceux qui ont été dénoncés, et les extirpe de leurs logements. Il semble que les prédictions de mes parents se réalisent. L'hystérie collecte morbide qu'ils ont connu envahit de nouveau la bourgade ! Et j'ai peur d'en être la prochaine victime !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Même mes propres cousins se sont mis à me regarder comme des chiens enragés, prêts à m'attaquer dès que j'aurai le dos tourné. Leur convoitise maladive les pousse à s'approprier mes découvertes. Je vois bien comme ils cherchent à jeter l'opprobre sur moi et à m'empêcher d'accomplir le grand œuvre de ma famille ! S'ils devaient basculer dans la démence, j'en aurais le cœur brisé, mais s'ils continuent de me harceler, je n'hésiterais pas à déchainer les feux de l'enfer. ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("De mon côté, je suis plus que jamais sûr de mon objectif. Je n\'ai qu\'un but dans " +
            "la vie et je ne céderai pas à la peur. Mon grand œuvre monopolise mes journées e" +
            "t je ne reculerai devant rien pour le voir se concrétiser !");
        yield return lineBreak();
        Vars.path4 = "PEForeign";
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "CommemorativeIntro", null);
        yield return lineBreak();
        Vars.brickvalue = macros1.either(1, 2);
        if (Vars.kill == "butcher")
        {
            Vars.wsuspect = "Apprenti de la bouchère";
        }
        else if (Vars.kill == "blacksmith")
