            if (Vars.wsuspect == "Apprenti du forgeron")
            {
                Vars.hexAI = macros1.either("Apprenti du forgeron", "Syndicat des Travailleurs");
            }
        }
        else if (Vars.players == 3)
        {
            Vars.pointAI = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            if (Vars.wsuspect == "Apprenti de la bouchère")
            {
                Vars.hexAI = macros1.either("Apprenti du Fermier", "Syndicat des Travailleurs");
            }
            if (Vars.wsuspect == "Apprenti du forgeron")
            {
                Vars.hexAI = macros1.either("Apprenti du forgeron", "Syndicat des Travailleurs");
