    IStoryThread passage14_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION II : Une monde plus civilisé");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre - ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(" ");
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("2 mars 1863. Roumanie.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Comme le disent si bien les marins, il y a toujours un moment de calme avant la tempête. De mon côté, je préfère dire qu'il y a une baisse de la pression atmosphérique avant la tempête. Et cet idiome s'applique parfaitement à mon horrible situation actuelle.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Le manoir est installé au-dessus d'un précipice, son imposant portail en fer forgé déchirant la forêt tel l'immense gueule d'une créature fantasmagorique. Vous avez sans nul doute admiré le daguerréotype le représentant, je ne m'étendrai donc pas sur le sujet. Je le voyais ainsi dans ma jeunesse, et revenir prendre possession de mon héritage provoquait en moi une certaine nervosité.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"il semble que les superstitions de l'ancien temps, tout comme le passé sombre de la ville, ne soient plus vraiment un sujet de discussion. L'idée selon laquelle justice a été rendue fait consensus. Les anciennes traditions laissent progressivement place à des valeurs plus modernes. De nombreux habitants prétendent même que ces événements n'ont jamais eu lieu. ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Mais les symptômes sous-jacents de l'hystérie collective sont toujours présents à travers de nouveaux modes de pensée rétrogrades et improductifs. Sans doute une manière pour eux d'oublier les actes honteux de leurs aïeuls. La région a décidé d'investir dans les dernières méthodes psychiatriques (absurdes et dont on ne connait pas encore les effets) et un terrain a déjà été préparé pour la construction d'un Refuge qui sera dédié au soin de l'esprit.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Ainsi, la ville était comme un loup qui lèche ses plaies : plongée dans un calme " +
            "tout relatif. Je pensais pouvoir profiter de cette tranquillité bienvenue pour r" +
            "eprendre mes travaux.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Mais c\'était avant de voir la Créature et son impressionnante carcasse rincée par" +
            " la pluie passer devant ma fenêtre l\'autre nuit.");
        yield return lineBreak();
        yield return lineBreak();
        Vars.mog = 0;
        Vars.path4 = "PECreature";
        yield return lineBreak();
        yield return link("Continue...", "CreatureDemands", null);
        yield return lineBreak();
        Vars.liber = 0;
        Vars.conse = 0;
        Vars.asupg = macros1.either(1, 2);
        Vars.asylumup = macros1.either("Refuge du Syndicat des Travailleurs", "Clé du Refuge", "Part du Refuge");
        Vars.did1 = macros1.either("le Chiot", "la Fiancée", "le Chiot et la Fiancée");
        Vars.curecount = 0;
        Vars.bhome = 0;
        Vars.crpg = 0;
        Vars.Acont = 0;
        Vars.Bcont = 0;
        Vars.Ccont = 0;
        Vars.Dcont = 0;
        Vars.Econt = 0;
        yield break;
    }


