    IStoryThread passage17_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION III : Isolement et ignorance");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre expédiée par ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("30 mars 1892. Roumanie.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Je vous le jure, ces satanés paysans sont en train de construire un mur qui encer" +
            "cle totalement leur propre ville. Au XIXe siècle ! Ces imbéciles ont mis de côté" +
            " la paranoïa pour une démence totale !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"S'attendent-ils à ce qu'une puissance étrangère vienne assiéger leur trou avec des trébuchets ? À quoi cela va-t-il leur servir, que diable ? Le commerce s'effondre, les prix explosent. Et par-dessus tout, puisque les marchands nomades ne viennent plus, je dois trouver d'autres sources d'approvisionnement pour élargir mes connaissances.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ainsi, cette semaine, j'ai dû supporter une intolérable intrusion dans mon intimité ! Alors que je descends d'une grande lignée, propriétaire légitime d'un immense domaine, j'ai dû me soumettre à une fouille personnelle indigne afin de pouvoir franchir la porte nouvellement construite de ma ville de naissance. Et ensuite ? Que devrai-je encore subir afin de prouver ma loyauté envers ma ville ? Ma moitié a été tellement choquée par le traitement imposé qu'elle est restée enfermée dans sa chambre toute la semaine, rongée par de mauvaises pensées.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Je maudis ce monde infernal dans lequel nous vivons, où l'on ne cesse de se heurter aux frustrations et aux complications en tous genres ! Ces tendances régressives et isolationnistes auraient sans doute pu s'exprimer autrement ! La situation me semble si désespérée qu'elle en ébranle ma nature profondément pragmatique. Comment imaginer changer le monde quand celui-ci refuse à ce point toute évolution ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Je vous fais le serment que ces remparts s\'effondreront avant qu\'ils ne détruisen" +
            "t mon esprit. Je trouverai comment contourner cette oppression pour préserver mo" +
            "n héritage, quel qu\'en soit le prix !");
        yield return lineBreak();
        yield return lineBreak();
        Vars.path4 = "PEIsolation";
        Vars.visit = 1;
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "IsoBricksRes", null);
        yield return lineBreak();
        if (Vars.townname == "Debug")
        {
            yield return text("v1.1");
        }
        yield break;
    }


