    }

    IStoryThread passage18_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION III : Vieilles habitudes");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal intime - ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("Avril 1892.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ah, quel soulagement de ne plus devoir de vivre chaque moment d'éveil dans la peur de finir sur le bûcher ! L'oppressante hostilité de la campagne roumaine, à laquelle j'ai dû m'habituer pendant ma jeunesse, a transformé mon retour en calèche dans ce vieux domaine familial en une épouvantable perspective.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Pourtant, l'encre séchait à peine sur les documents testamentaires que ma moitié et moi profitions d'un bon café à la terrasse d'une rue pavée. Les seuls regards qui se sont posés sur nous étaient attirés par nos flamboyantes tenues parisiennes. Pas un seul regard de travers nous laissant croire que nous pourrions être abattus d'un tir de revolver ou poignardés vicieusement. C'en était presque décevant.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"La décision de la ville de renoncer à la construction d'une enceinte fortifiée, et la disparition des tensions xénophobes ont permis l'émergence de nouveaux commerces et une plus grande ouverture vers les autres cultures. Je parviens ainsi à recevoir des invités exotiques qui piquent ma sinistre curiosité. L'occultisme et les superstitions qu'il a répandu dans ma famille sont devenus une incroyable source de fascination. Le spiritisme est à la mode de nos jours, vous savez.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Toutefois, « les vieilles habitudes ont la peau dure » comme le dit le dicton, et de délicieuses tensions rongent doucement la ville de l'intérieur. L'acceptation (ou l'apathie) a peut-être étouffé les haines tempétueuses, mais je constate que cette infection psychologique profonde n'a pas tout à fait disparu. À chaque rencontre, je sens que mes actes poussent ces différentes factions à se rapprocher jusqu'au point où elles seront obligées de prendre des décisions potentiellement toutes aussi amusantes que dévastatrices.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("C\'est déjà une expérience en soi, comme un baril de poudre sur le point d\'explose" +
            "r. Et je suis impatient d\'en observer le résultat.");
        yield return lineBreak();
        Vars.path4 = "PETension";
        Vars.visit = 2;
        Vars.tensegood = 0;
        Vars.tensebad = 0;
        Vars.ten = 0;
        Vars.eor = 0;
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "TensionSetting", null);
        yield return lineBreak();
        if (Vars.townname == "Debug")
        {
            yield return text("v1.1");
        }
        yield break;
    }


