    }

    IStoryThread passage23_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION III : Une affaire qui roule");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre expédiée par ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("9 février 1892. Roumanie.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cette lettre sera brève, aussi brève que possible. Vous savez que la concision n'est pas ma qualité première. Mais nous sommes en plein hiver, l'encre peine à sécher à cause de l'humidité, et mon esprit est encombré de problèmes insolubles. Peut-être aurait-il été plus convenable d'écrire ces quelques mots avec mon propre sang, s'il est aussi froid que le pensent les tristes habitants de cette ville grise et sans âme. Cela leur aurait au moins apporté une touche de couleur.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Vous vous intéressez sans doute plus à mes affaires, et elles se portent extrêmement bien, ou plutôt devrais-je dire que j'ai du mal à garder les chiffres en tête. J'avais investi personnellement dans cette ville et le bien-être de ses habitants, et je me retrouve propriétaire d'une grande partie du quartier commerçant. Malheureusement, mes bons cousins (que j'adore pourtant) ont également investi. Et il s'avère que nos investissements familiaux sont exceptionnellement rentables.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Grande nouvelle du jour : le Programme du Refuge, que je pensais sans intérêt au début, se révèle être une intrigante source d'inspiration. Ne vous méprenez pas, je ne me suis pas subitement adepte de ces histoires de réhabilitation de l'esprit, mais je pense qu'un traitement plus strict que celui qu'ils cherchent à administrer serait plus efficace. Avec une contribution financière de notre part et l'approbation de l'état, une prison pourrait représenter le parfait terrain d'expérimentation.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Quanft à moi, je vais bien. Mes recherches avancent et provoquent toujours chez moi une immense passion qui me consume de l'intérieur plus que tout au monde. Même le brouillard lugubre qui encombre cette morne vallée m'emplit d'un calme imperturbable. Pourtant, c'est bien ce calme-là qui provoque mon malaise.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Je dois progresser rapidement car je sens une présence. Quelque chose m\'observe, " +
            "prête à bondir de l\'obscurité. Il est hors de question que ma grandiose destinée" +
            " ne m\'échappe alors que je suis sur le point d\'en atteindre l\'apogée !");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "PrivatetoJail", null);
        yield return lineBreak();
        Vars.exped = 0;
        Vars.hunt = 0;
        Vars.path4 = "PEPrivatized";
        if (Vars.townname == "Debug")
        {
            yield return text("v1.1");
        }
        if (Vars.kill == "butcher")
        {
            Vars.warden = "La bouchère";
        }
        if (Vars.kill == "blacksmith")
        {
            Vars.warden = "Le Ravageur";
        }
        Vars.junkpenalty = macros1.either("Perdez <b>5</b> PV", "Défaussez un <b>Aménagement Fastueux</b> de votre Domaine, si possible.");
        Vars.creepcount = 0;
        yield return lineBreak();
        yield break;
    }


