    // #24: LiberalIntro

    void passage24_Init()
    {
        this.Passages[@"LiberalIntro"] = new StoryPassage(@"LiberalIntro", new string[] { "INTRO", "revised", "Trad-FR", }, passage24_Main);
    }

    IStoryThread passage24_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION III : Acceptation");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre expédiée par ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("9 février 1892. Roumanie.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Je tiens à vous présenter mes excuses pour ma réponse si tardive. Régler les détails de cette succession a fait remonter d'affligeants secrets qui tourmentent mes journées. La situation est terrible. Par terrible, j'entends tout aussi bien convenable ou réjouissante que douloureusement ennuyeuse. Les gens se promènent dans une ville accueillante, se saluent avec le sourire et partagent des gâteaux. Des gâteaux ! Peuvent-ils être si étrangers à la triste réalité du monde qui les entoure ? Comment peuvent-ils se permettre de se comporter d'une manière aussi atrocement positive ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Alors que toutes les autres institutions d'Europe sont frappées par le fléau de la surpopulation, le repère d'aliénés de notre bonne ville semble être le phare mondial de réhabilitation mentale. L'enfermement et les restrictions ont été remplacés par des soins personnels adaptés, et un programme de réinsertion par le travail a été développé pour les patients désireux de retrouver une place dans la société, armés des compétences nécessaires.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"En théorie, le concept est séduisant, mais nous savons qu'il ne peut conduire qu'à la démence. Lorsque j'ai voulu me rendre sur place pour découvrir ce Programme du Refuge (comme ils l'appellent si pompeusement), ils ont essayé de m'évaluer comme si j'avais été admis en soins ! Ce pays semble s'être doté de moyens plus courtois de priver les citoyens qu'il craint de leurs libertés, sans parler des nouvelles taxes imposées aux entrepreneurs tels que moi.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Tel le puissant Atlas, je supporterai toutes ces charges sans faiblir. Bien que je désapprouve la méthode, les dépenses liées à une telle approche progressiste nous menant sans doute à la banqueroute, je dois reconnaitre qu'avoir facilement accès à une main-d'œuvre qualifiée n'est pas pour me déplaire, en espérant que ces potentiels assistants n'aient pas froid aux yeux.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Les journées sont radieuses dans cette belle vallée, mais elles seront encore plu" +
            "s rayonnantes lorsqu\'elles seront illuminées par l\'œuvre géniale de ma famille !" +
            " ");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "LiberalHomeTile", null);
        yield return lineBreak();
        Vars.exped = 0;
        Vars.path4 = "PELiberal";
        if (Vars.townname == "Debug")
        {
            yield return text("v1.1");
        }
        Vars.asylumcount = 0;
        yield break;
    }


