        //yield return text(" ");
        //yield return text("inutilisée dans la boite. ");
        //if (Vars.bhome == 0 || Vars.bhome == "")
        //{
        //    yield return text("Remettez la tuile ");
        //    using (styleScope("bold", true))
        //    {
        //        yield return text("Maison sur la Colline");
        //    }
        //    yield return text("dans la boite Scénario.");
        //}
        //yield return lineBreak();
        //yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Au soutien de la Créature");
        }
        yield return lineBreak();
        Vars.Gen2fate = "creature";
        string s = "Retirez du plateau tous les pions des joueurs et appliquez les effets de fin de G" +
            "énération. Remettez toute tuile " + Vars.asylumup + " inutilisée dans la boite. ";
        if (Vars.bhome == 0) s += "Remettez la tuile <b>Maison sur la Colline</b> dans la boite Scénario.";
        ViewEndOfGeneration.S_OnEndOfGeneration?.Invoke(s, 6);
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettres diverses - ");
            using (styleScope("italic", true))
            {
                yield return text("Shelley, Herbert - Février 1892.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.creature == 2)
        {
            yield return text(@"Votre précédente lettre a manifestement été écrite dans l'urgence et se termine par des griffonnages incohérents. Quelle est donc cette histoire de créature, et pourquoi avez-vous échoué « devant Dieu » à « aider cette pauvre chose » ? Votre propre santé mentale ne serait-elle pas touchée ? ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("J\'ai entendu dire que ");
            using (styleScope("bold", true))
            {
                yield return text("le Refuge avait été agrandi");
            }
            yield return text(@". Votre récent goût pour la charité est peut-être à l'origine de cette action caritative. Que ce soit le cas ou non, n'hésitez pas à vous y rendre. Pas forcément pour vous faire interner, à moins que vous ne souhaitiez vous-même, mais ils pourront peut-être vous indiquer un remède qui apaiserait vos angoisses. J'ai peur qu'il vous faille plus qu'une tasse de thé et une bonne nuit de sommeil.");
            yield return lineBreak();
            yield return lineBreak();
            Vars.Gen2End = "asylum";
            yield return link("Cliquez pour continuer...", "S4BadCreature", null);
        }
        if (Vars.creature == 1)
        {
            yield return text("Quelle est donc cette histoire sans queue ni tête de ");
            using (styleScope("bold", true))
            {
                yield return text("créature rôdant librement dans les parages");
            }
            yield return text("? Je me permets de vous poser la question car vos dernières lettres parlant de vo" +
            "s récentes expérimentations n\'étaient pas très parlantes.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Je ne cautionne parfois pas vos méthodes mais j'ai toujours essayé de vous soutenir en tant qu'universitaire. Cependant, libérer dans la nature et sans surveillance un monstre qui, d'après de nombreux récits, vole et tue sans vergogne sur son passage, c'est une raison largement suffisante pour mettre un terme à notre amitié.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Votre décision a poussé la population à ");
            using (styleScope("bold", true))
            {
                yield return text("remettre en cause la sécurité du Refuge");
            }
            yield return text(", pensant que les fous couraient les rues. Et je ne vois vraiment pas comment on " +
            "pourrait l\'en blâmer.");
            yield return lineBreak();
            yield return lineBreak();
            Vars.Gen2End = "jail";
            yield return link("Cliquez pour continuer...", "S4BadCreature", null);
        }
        yield return lineBreak();
        yield break;
    }


