            yield return lineBreak();
            yield return text(@"Je n'ai plus un sou ! Oh, quelle naïveté que la mienne. Je n'aurais pas dû ignorer les avertissements de mes parents. Ils avaient vu juste ! Mais j'ai péché par fierté, ignorant ces vieilles superstitions et ces croyances inconcevables comme le mauvais sort !");
