    // .............
    // #46: CreatureDemands

    void passage46_Init()
    {
        this.Passages[@"CreatureDemands"] = new StoryPassage(@"CreatureDemands", new string[] { "INTRO", "Trad-FR", }, passage46_Main);
    }

    IStoryThread passage46_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Les exigences de la créature");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre expédiée par ");
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("(suite)");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"À ma grande surprise, ce monstre hideux parle. Sa mâchoire, grossièrement cousue à son visage par un épais fil noir, laisse apparaitre ses muscles internes lorsqu'elle bouge. De sa voix profonde et gutturale, il exprime sa haine viscérale envers mon grand-père qui l'a créé puis abandonné à son triste sort en pleine nature. « J'ai été abandonné comme un moins-que-rien alors que ces enfants se vautraient dans le luxe », gémit-il.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Il parait que les péchés d'un père sont le fardeau de ses enfants, et il est rare qu'une génération y échappe. « Vous avez une immense dette envers moi, et je suis venu exiger son paiement », dit-il d'un ton ferme, tout en m'obligeant à écouter son récit jusqu'au bout. J'ai été abasourdi par ces paroles menaçantes et cette révélation : les obscurs secrets de notre famille étaient donc bien réels.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Forcée de vivre malgré son apparence repoussante, la création de mon grand-père exigeait de vivre accompagnée d'un être fidèle qui pourrait comprendre la torture de son existence. Et qu'il était du devoir de ma famille de le créer pour elle afin d'expier ses péchés !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Elle se retourna une dernière fois, la lune éclairant son visage difforme. Elle j" +
            "ura que si nous ne le faisions pas, nous subirions tous sa terrible vengeance, e" +
            "t que nous ressentirions brutalement tout ce qu\'elle a enduré !  ");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "TheCreatureCard", null);
        yield break;
    }


