    IStoryThread passage52_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("La Créature a été abattue");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal intime - ");
            using (styleScope("italic", true))
            {
                yield return text("nom illisible");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Victoire ! Oh, je doute que les mots puissent décrire correctement le regard déconfit sur le visage déformé de cette monstruosité lorsqu'elle a compris que sa vie touchait à sa fin ! Mes domestiques et moi avons maitrisé l'ignoble créature avant de lui ligoter les chevilles et les poignets autour du tronc d'un bouleau que nous venions d'abattre.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Nous avons allumé un feu à l'aide d'écorces et d'aiguilles de pin, et j'ai profité du spectacle de la fumée se transformant en flammes qui consumaient doucement le monstre. D'abord ses pieds et ses jambes couverts de vêtements déchirés, puis sa boucle de ceinture brûlante lui déchirant la chair alors qu'elle tombait dans le feu, portée au rouge par l'intense chaleur du brasier");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Elle n'a pas crié, ne s'est pas débattue dans son agonie, comme si la douleur de sa propre existence l'avait empêchée de ressentir toute autre sensation. Elle m'a simplement adressé un regard désespéré, comme si le monde entier l'avait abandonnée. Je n'ai pas supporté ce regard. J'ai sorti mon pistolet et j'ai mis fin à ses souffrances.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage52_Fragment_5);
        using (styleScope("hook", "h00005205"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h00005205", HarloweEnchantCommand.Replace, passage52_Fragment_4));

        yield return lineBreak();
        yield break;
    }

