    // .............
    // #54: LiberalEvent

    void passage54_Init()
    {
        this.Passages[@"LiberalEvent"] = new StoryPassage(@"LiberalEvent", new string[] { "Trad-FR", }, passage54_Main);
    }

    IStoryThread passage54_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Stimuler l\'économie");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return passage("letter1a");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Comme je l'avais prédit, les coûteux programmes sociaux du gouvernement roumain ont rapidement vidé ses caisses alors que le pays connaissait une brève récession. J'avais diversifié une bonne partie de mon portefeuille à l'étranger, l'impact sur mon capital a donc été négligeable. Dans le même temps, les bouleversements provoqués par la Grande Guerre ont fait remonter les nationalismes et les mouvements d'indépendance dans toute la Transylvanie.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("La protection des nôtres est soudain devenue l\'obsession du gouvernement. Les dis" +
            "cussions politiques me font bâiller dès qu\'elles s\'éternisent un peu. Ce n\'est t" +
            "oujours que babillages sans fin sur les races, les droits de l\'homme ou la relig" +
            "ion.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Quoi qu\'il en soit, ces décisions ont conduit la Transylvanie dans une impasse do" +
            "nt il ne sortira rien de bon. En tant que propriétaires terriens et entrepreneur" +
            "s, nous pèserons à coup sûr sur les prochaines orientations des autorités locale" +
            "s.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.players == 2)
        {
            yield return link("Cliquez pour continuer...", "2PLiberalEvent", null);
        }
        else
        {
            yield return link("Cliquez pour continuer...", "LiberalEvent1", null);
        }
        yield return lineBreak();
        yield return lineBreak();
        yield break;
    }


    // .............
    // #55: StoryBook

    void passage55_Init()
    {
        this.Passages[@"StoryBook"] = new StoryPassage(@"StoryBook", new string[] { "Trad-FR", }, passage55_Main);
    }

    IStoryThread passage55_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Comment utiliser le livret Histoire");
        }
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Le Secret de mon Père");
        }
        yield return text(" ");
        yield return text(@"est un jeu mettant en scène d'ambitieux et insensés scientifiques à l'ère victorienne, et le jeu se déroule sur trois générations. Cette application, appelée le livret Histoire, contrôle la direction dans laquelle la ville va s'engouffrer en fonction des décisions prises par les joueurs. Les joueurs devront interagir avec l'application en cliquant sur des liens à certains moments précis.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Fin d\'une manche");
        }
        yield return lineBreak();
        yield return text("Il y a trois manches par Génération. À la fin de chaque manche, vous ");
        using (styleScope("bold", true))
        {
            yield return text("devez");
        }
        yield return text(" ");
        yield return text("cliquer sur le lien du bas de l\'écran pour déclencher des événements spéciaux et " +
            "aller à la manche suivante. L\'écran indiquera ensuite la manche suivante et les " +
            "changements à appliquer au jeu (le cas échéant).");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Actions de Scénario");
        }
        yield return text(" ");
        yield return text("<sprite=\"StorybookToken\" index=0>");
        yield return lineBreak();
        yield return text(@"Parfois, le jeu demandera à un joueur de cliquer un certain lien lorsqu'une action spécifique a été accomplie. Cela peut être déclenché par une action en ville ou dans votre domaine, ou pour avoir accompli un objectif spécifique. Assurez-vous de bien cliquer sur ces liens : cela déclenchera des événements spéciaux pour vous.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour revenir en arrière...", "Start2", null);
        yield return lineBreak();
        yield return lineBreak();
        yield break;
    }


