    // .............
    // #70: Witchwolfresolution

    void passage70_Init()
    {
        this.Passages[@"Witchwolfresolution"] = new StoryPassage(@"Witchwolfresolution", new string[] { "Trad-FR", }, passage70_Main);
    }

    IStoryThread passage70_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Accusations");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return passage("letter1a");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les rumeurs se propagent vite par ici. Bien que je tienne à distance du monde civilisé, je m'isole également de toutes formes d'activité notable. Je suppose que vous avez déjà eu vent de la récente tragédie familiale, toutefois je souhaitais vous en faire part personnellement.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"En tant que cousins, nous dînons régulièrement ensemble. Malheureusement, nous nous sommes réunis une nuit mauvaise où le vent hurlait à la mort et envoyait les branches des acacias taper contre les fenêtres du domaine. Lors de cette terrible soirée, nous aperçûmes une grande lueur provenant de la forêt. Très vite, une multitude de villageois se massèrent devant nos grilles, agitant des torches et brandissant des fourches. ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les villageois nous accusèrent d'être la source des sortilèges qui affligeaient la région. Cette nuit-là, ils exigèrent un sacrifice, et aucune tentative de négociation ne permit d'apaiser leur soif de sang. Alors que les chiens les tenaient à distance, nous fûmes forcés de prendre une décision sordide qui nous hantera jusqu'à la fin de nos jours.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "Witchres", null);
        yield return lineBreak();
        yield break;
    }


    // .............
    // #71: WallEvent

    void passage71_Init()
    {
        this.Passages[@"WallEvent"] = new StoryPassage(@"WallEvent", new string[] { "Trad-FR", }, passage71_Main);
    }

    IStoryThread passage71_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Mémorial du passé pour le futur");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return passage("letter1a");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Comme je m'y attendais, et je vous en avais déjà fait part, un brin amusé, la ville n'a pas reçu le soutien financier escompté pour la construction de son mémorial. Par contre, je suis beaucoup moins amusé par l'interruption de mes expérimentations, alors que j'espérais enfin pouvoir profiter d'un peu de tranquilité. Pas plus tard qu'hier, des représentants des autorités locales en costume (ou du moins ce que de vieux ringards prétentieux appellent un costume) sont venus au domaine en personne pour requérir mon aide.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Lorsque j'ai insisté pour savoir ce qu'ils faisaient effectivement de notre argent, ils se sont mis à agir comme des perruches dont on secouerait la cage : ils gesticulaient et parlant le plus vaguement du monde d'éradiquer les superstitions et les mauvaises influences qui pèsent sur la ville, promettant de la rendre à nouveau prospère. Grande serait ma surprise, s'ils y parvenaient.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Mes relations avec les marchands tsiganes du coin m'ont permis d'échanger avec eux sur le sujet : pour eux, il est clair que, quelles que soient les opnions de la bourgade, le mémorial aura de grosses répercutions sur leurs affaires. Ils ne souhaitent pas quitter la région, mais ils le feront si on les pousse à le faire.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "WallEvent1", null);
        yield return lineBreak();
        yield break;
    }


