    IStoryThread passage82_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("La chasse aux sorcières");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal - ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("2 Décembre 1862.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les villageois étaient de plus en plus dérangés par ma présence, prétendant que ma famille était maudite et que tous ceux qui s'en approchaient connaissaient un destin tragique. Après la disparition prématurée de plusieurs partenaires commerciaux de la famille, et l'apparition de pentagrammes de sang un peu partout en ville, je me mis moi-même à douter. Était-ce la manifestation d'un force surnaturelle, une sorte de malédiction lancée contre l'un d'entre nous, ou un simple hasard ? ");
        if (Vars.players <= 3)
        {
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Nous ne pouvions pas écarter la possibilité qu\'il s\'agisse d\'une vengeance malavi" +
            "sée de la part de l\'");
            yield return text(Vars.wsuspect);
            yield return text(", qui chercherait à nuire à l\'ensemble de la famille. J\'avais remarqué que j\'étai" +
            "s suivi lors de mes premières sorties en ville, et les événements des dernières " +
            "décennies ne font qu\'accentuer mes soupçons.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Alors que les villageois basaient leurs accusations sur de vieilles superstitions" +
            ", nous, les intellectuels, avions décidé d\'utiliser la science, comme il se doit" +
            ", pour déterminer lequel d\'entre nous était maudit.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "WitchIntro2", null);
        yield return lineBreak();
        yield break;
    }


