    IStoryThread passage84_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Châtiment");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return passage(Vars.journal1a);
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ils étaient supposés se déchirer ! En venir aux mains ! Il n'y avait pas d'autre issue possible ! Une réunion animée était prévue aujourd'hui en ville, l'ambiance devait à coup sûr s'apparenter à un volcan sur le point d'entrer en éruption. Mais voilà, j'ai attendu sous ma véranda que la ville se consume jusqu'à ce que mon thé soit froid.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("La nouvelle n\'est arrivée par porteur que plusieurs heures plus tard. D\'après com" +
            "ptes-rendus, il semblerait que, de toute l\'histoire de ");
        yield return text(Vars.townname);
        yield return text(", il n\'y eu qu\'une seule et unique malédiction : nous. Les choix de notre famille" +
            " à travers les générations ont eu un impact majeur sur les tensions qui ont touj" +
            "ours régné sur la ville.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Ils ont pris le temps d\'analyser les événements. ");
        if (Vars.kill == "butcher")
        {
            Vars.tensebad = int.Parse(Vars.tensebad) + 1;
            yield return text("La sombre histoire de nos grand-parents et leur choix d\'encourager la mise à mort" +
            " d\'une ");
            using (styleScope("bold", true))
            {
                yield return text("personne innocente");
            }
            yield return text("figure en bonne place dans les registres de la ville..");
        }
        if (Vars.kill == "blacksmith")
        {
            Vars.tensegood = int.Parse(Vars.tensegood) + 1;
            yield return text("Bien que la justice de la ville se soit souvent montrée défaillante, le choix de " +
            "nos grand-parents de pendre le ");
            using (styleScope("bold", true))
            {
                yield return text("désigné coupable");
            }
            yield return text("résonne encore.");
        }
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.cursed == 2)
        {
            Vars.tensebad = int.Parse(Vars.tensebad) + 1;
            yield return text("L");
            using (styleScope("bold", true))
            {
                yield return text("\'incapacité");
            }
            yield return text("de nos ancêtres ");
            using (styleScope("bold", true))
            {
                yield return text("à démasquer la maudite sorcière");
            }
            yield return text("est encore bien présente dans leurs esprits.");
        }
        if (Vars.cursed == 1)
        {
            Vars.tensegood = int.Parse(Vars.tensegood) + 1;
            yield return text("Le fait que nos ancêtres soient parvenus ");
            using (styleScope("bold", true))
            {
                yield return text("à démasquer la maudite sorcière");
            }
            yield return text("a été considéré comme une réussite notoire.");
        }
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.walls == "yes")
        {
            Vars.tensebad = int.Parse(Vars.tensebad) + 1;
            yield return text("Les Tsiganes ont encore en mémoire notre piètre décision de ");
            using (styleScope("bold", true))
            {
                yield return text("fortifier");
            }
            yield return text("la ville.");
        }
        if (Vars.walls == "no")
        {
            Vars.tensegood = int.Parse(Vars.tensegood) + 1;
            yield return text("Les Tsiganes se souviennent que nous avons fait ");
            using (styleScope("bold", true))
            {
                yield return text("le choix de l\'ouverture");
            }
            yield return text("et que nous avons refusé de soutenir la politique malavisée de la ville.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("L\'ensemble des villageois a pris tous ces éléments en compte, et ils sont rapidem" +
            "ent parvenus à un accord.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.tensebad > Vars.tensegood)
        {
            Vars.tension = "bad";
            yield return link("Cliquez pour continuer...", "ThistenseBad", null);
        }
        if (Vars.tensegood > Vars.tensebad)
        {
            Vars.tension = "good";
            yield return link("Cliquez pour continuer...", "ThistenseGood", null);
        }
        yield return lineBreak();
        yield break;
    }


