        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Scandaleux ! Nos représentants au parlement ont répondu vivement à notre courrier, nous interdisant d'exercer notre influence dans la sphère démocratique. Oseraient-ils laissé la populace influer sur une décision si importante ? Cet incroyable manque de respect dépasse tout ce que mon esprit scientifique supérieur pourrait endurer !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Non, il est clair qu'ils cherchent à soutirer le maximum d'argent de nos coffres. Cela sous-entend que nous n'avons pas encore fourni suffisamment de fonds pour faire basculer la décision, et nous l'avons bien compris. Si nous voulons que notre volonté fasse office de loi, nous allons devoir les soudoyer.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Un pot-de-vin de ");
        using (styleScope("bold", true))
        {
            yield return text(Vars.bribed);
            yield return text("$");
        }
        yield return text(" ");
        yield return text("devrait suffire. Ou sinon, nous pouvons aussi nous en remettre à la décision du p" +
            "euple.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "LiberalEvent2a", null);
        yield return lineBreak();
        yield break;
    }


