                    yield return text("(suite)");
                }
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Malgré des preuves évidentes, le jury du tribunal ne s'est pas accordé sur une condamnation de mes investissements douteux. Plusieurs témoins ont pu attester du comportement excentrique de ma famille. Bien que cela n'ait pas forcément rassuré les juges, l'argument les a convaincu d'abandonner les poursuites contre moi, sans la moindre amende.");
