            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage91_Fragment_1);
            using (styleScope("hook", "h00009101"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h00009101", HarloweEnchantCommand.Replace, passage91_Fragment_0));

        }
        if (Vars.pay == 0 || Vars.pay == "")
        {
            if (Vars.trial == 0 || Vars.trial == "")
            {
                using (styleScope("bold", true))
                {
                    yield return text("Victoire");
                }
                yield return lineBreak();
                yield return lineBreak();
                using (styleScope("bold", true))
                {
                    yield return text("Lettre expédiée par ");
                    yield return text(Vars.tempid);
                    yield return text("- ");
                    using (styleScope("italic", true))
                    {
                        yield return text("(suite)");
                    }
                }
                yield return lineBreak();
                yield return lineBreak();
                yield return text(@"Malgré des preuves évidentes, le jury du tribunal ne s'est pas accordé sur une condamnation de mes investissements douteux. Plusieurs témoins ont pu attester du comportement excentrique de ma famille. Bien que cela n'ait pas forcément rasuré les juges, l'argument les a convaincu d'abandonner les poursuites contre moi, sans la moindre amende.");
                yield return lineBreak();
                yield return lineBreak();
                //yield return enchantIntoLink("Cliquez pour continuer...", passage91_Fragment_3);
                using (styleScope("hook", "h00009103"))
                    yield return link("Cliquez pour continuer...", null, () => enchantHook("h00009103", HarloweEnchantCommand.Replace, passage91_Fragment_2));

            }
            if (Vars.trial == 1)
            {
                using (styleScope("bold", true))
                {
                    yield return text("Honteuse Condamnation Publique");
                }
                yield return lineBreak();
                yield return lineBreak();
                using (styleScope("bold", true))
                {
                    yield return text("Lettre expédiée par ");
                    yield return text(Vars.tempid);
                    yield return text("- ");
                    using (styleScope("italic", true))
                    {
                        yield return text("(suite)");
                    }
                }
                yield return lineBreak();
                yield return lineBreak();
                yield return text(@"Si vous saviez à quel point le dossier monté contre moi était bancal ! De nombreux témoins ont corroboré mes connexions avec le milieu local de la contrebande (tout à fait absurde), mais ces rustres n'étaient même pas capables de livrer un témoignage qui tienne debout.");
                yield return lineBreak();
                yield return lineBreak();
                yield return text(@"Nous n'avons affaire qu'à des simples d'esprit. Le juge, dans son emballement, a considéré que ces quelques preuves étaient suffisantes pour me condamner. Bien que les frais de justice soient limités, et l'amende négligeable, la vindicte populaire qui en résultera pourrait bien menacer ma capacité à achever tranquillement mon œuvre.");
