            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("(suite)");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("L\'action prit tristement fin aussi vite qu\'elle avait commencé. ");
        if (Vars.ex == "bio")
        {
            yield return text("Notre Gorille, qui avait atteint la taille d\'une petite maison, frappa une derniè" +
            "re fois ses poings puissants contre sa poitrine dans un rugissement qui nous sec" +
            "oua l\'oreille interne, même à plus d\'un kilomètre, avant de perdre l\'équilibre.");
        }
        if (Vars.ex == "chem")
        {
            yield return text(@"Le Tissu tourbillonna une dernière fois dans les airs, éjectant un passant avec une telle force que son corps vola bien au-delà de l'enceinte de la ville. Un grand éclair vint claquer à sa surface puis il se mit à descendre paresseusement, comme s'il se laissait porter par le vent.");
        }
        if (Vars.ex == "eng")
        {
            yield return text("Notre Robot envoya un immense souffle de vapeur sur la foule alentour. Les brûlés" +
            " se mirent à crier en se tenant les yeux, juste avant que ses rouages ne se grip" +
            "pent au beau milieu de la rue.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Notre création s'étala au sol, inanimée, entourée des gravats et des morceaux de métal, de bois, et de chair fumante qu'elle venait d'éparpiller. Nous aurions préféré voir notre expérience exploiter pleinement son potentiel, mais le nuage de poussière et les destructions engendrées ainsi restaient dans le domaine de l'acceptable.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les villageois se précipitaient dans les rues pour essayer d'éteindre les incendies qui s'étaient déclarés dans toute la ville pendant que nous profitions d'un bon café chaud depuis notre lieu d'observation isolé, en disuctant des résultats. Le Science peut parfois être si satisfaisante.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage100_Fragment_1);
        using (styleScope("hook", "h000010001"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000010001", HarloweEnchantCommand.Replace, passage100_Fragment_0));

        yield return lineBreak();
        yield break;
    }

