    void passage101_Init()
    {
        this.Passages[@"LiberalTaxes"] = new StoryPassage(@"LiberalTaxes", new string[] { "Trad-FR", }, passage101_Main);
    }

    IStoryThread passage101_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("La mort du patrimoine");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return passage("letter1a");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Des taxes sur un héritage ? Avez-vous déjà entendu telle baliverne ? Il semble qu" +
            "e les autorités du comté aient décidé de prélever un impôt sur la succession des" +
            " citoyens les plus riches.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Notre partie de croquet matinale a été malencontreusement interrompue par l'arrivée de cette nouvelle. Cette fadaise progressiste m'a fait perdre toute capacité à franchir les arceaux au point que ma moitié a remporté la partie avant même que je ne parvienne à en passer un. Le prestige d'un domaine n'a-t-il donc qu'une valeur pécuniaire aux yeux de ces sangsues ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ils prétendent que c'est indispensable au bon fonctionnement du Refuge et d'autres services modernes comme l'école publique et le système de santé. S'ils étaient capables de faire fonctionner ces établissements de manière rentable, ils ne seraient pas obligés de saigner leurs électeurs !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cette nouvelle nous a tellement choqués que ma moitié et moi avons dû rester plus" +
            "ieurs jours au repos complet pour nous remettre de cette violente intrusion dans" +
            " nos affaires !");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "LiberalTaxes1", null);
        yield return lineBreak();
        yield break;
    }


