    IStoryThread passage112_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("L\'espoir est éternel");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return passage("journal1a");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le paquet est arrivé ! La fiole de sels essentiels est en parfait état et bien fe" +
            "rmée par un bouchon en liège scellé. Elle est minuscule mais je m\'y attendais. U" +
            "ne petite étiquette est attachée, avec une phrase en Énochien ; « Yogg-Sothoth N" +
            "eblod Zin. »");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Note de l'après-midi : les expériences initiales se sont avérées prometteuses. Je suis parti d'un lapin saigné et écorché depuis quelques. La formule indiquée par Joseph Curwen a provoqué l'apparition d'une fumée gris-vert autour de la carcasse. Et en quelques minutes, j'ai pu apercevoir l'animal mort tressauter, puis commencer à essayer de se libérer de ses liens ! Revenu d'entre les morts !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Maintenant que la Créature a été abattue, plus rien ne peut m\'empêcher d\'assouvir" +
            " mon plus profond désir ! Il est temps de ramener mon amour à la vie et de retro" +
            "uver la joie intense que nous partagions !");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "EssentialSalts1", null);
        yield return lineBreak();
        yield return lineBreak();
        yield break;
    }


