        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Dans un nuage de fumée émeraude, j\'ai vu les restes de mon épouse décédée rajeuni" +
            "r et reprendre la silhouette parfaite sous laquelle je l\'avais connue dans ma je" +
            "unesse. J\'avais réussi !");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.saltsp == 1)
