            yield return lineBreak();
            yield return lineBreak();
            yield return text("Je l\'ai embrassée, et bien qu\'elle fut étonnée par nos quelques décennies d\'écart" +
            ", elle m\'embrassa à son tour. Je suis un véritable génie !");
            yield return lineBreak();
            yield return lineBreak();
        }
        if (Vars.saltsp == 2)
        {
            yield return text("Toutefois, son tempérament s\'avéra instable. Un soir, elle a violemment ouvert le" +
