    // #118: TenseEventBad2

    void passage118_Init()
    {
        this.Passages[@"TenseEventBad2"] = new StoryPassage(@"TenseEventBad2", new string[] { "Trad-FR", }, passage118_Main);
    }

    IStoryThread passage118_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Comment apaiser les tensions ?");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return passage("letter1a");
        yield return lineBreak();
        Vars.obsvp = macros1.either(4, 5, 6);
        yield return lineBreak();
        yield return text(@"J'ai plongé au plus profond des ténèbres et j'ai vu la noirceur de l'âme humaine. Ils rôdent dans mes rêves comme des corps frais enveloppé d'un brouillard putride. Leurs mains froides s'accrochent à ma chemise de nuit. Lorsqu'ils ont fini de m'encercler, que je ne vois plus qu'un mur de chair en décomposition, je me réveille en hurlant.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ces cauchemars récurrents ne font qu'amplifier l'angoisse qui me prend lorsque j'observe par la fenêtre ce village gris et froid que j'ai tant aimé autrefois. Leur trahison me mure dans une solitude désespérante, me privant de tout accès aux ressources dont j'aurais besoin. Si seulement ils pouvaient comprendre l'importance de mes expériences. Si seulement ils pouvaient savoir à quel point je me soucie de leur sort !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ils m'ont déjà fait subir bien plus que je ne mérite, pourquoi s'acharnent-ils à me priver des ressources qui me manquent tant ? Il me les faut, tant pis si je dois user de stratagèmes malveillants pour me les fournir, je resterai fidèle à mes convictions. Mais j'aurai besoin de l'aide de mes cousins pour y parvenir. J'ai prévu de leur écrire dès demain.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.players == 2)
        {
            yield return link("Cliquez pour continuer...", "2PTenseEvent1", null);
        }
        else
        {
            yield return link("Cliquez pour continuer...", "TenseEventBad2b", null);
        }
        yield return lineBreak();
        yield break;
    }


