            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("27 Août 1862.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Malgré la morosité ambiante et les délations à tout va, je crois sentir une envie" +
            " de stabilité et un retour des valeurs qui ont forgé ");
        yield return text(Vars.townname);
        yield return text(", notre belle ville. Les représentants de la ville ont lancé une collecte de fond" +
            "s pour un vague projet de mémorial. Je ne suis pas sûr que ces âmes corrompues s" +
            "achent réellement de quoi il s\'agit.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le projet me semble voué à l\'échec. Toutefois, si faire apparaitre mes initiales " +
            "sur une brique me permettait d\'éloigner les protestataires de ma porte, je pourr" +
            "ais me sentir obliger de participer, à contrecœur.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage123_Fragment_1);
        using (styleScope("hook", "h000012301"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000012301", HarloweEnchantCommand.Replace, passage123_Fragment_0));

        yield return lineBreak();
        yield break;
