        yield return lineBreak();
        Vars.whpg = 1;
        yield return lineBreak();
        yield return text(@"Un entrepreneur et inventeur de notre ville attire de plus en plus l'attention de la population, mais pas forcément pour de bonnes raisons. Alors que ses expérimentations explosives et extravagantes se sont ébruitées, son ambition déraisonnable fait resurgir de vieilles légendes sur l'héritage sulfureux de la famille.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les exploits de cette lignée d'entrepreneurs ont déjà beaucoup fait parler dans le passé.  « Je recherche la gloire et la fortune », proclame volontiers l'aristocrate, sans autre forme d'introduction. « Et je les aurai. Laissez-moi donc vous faire découvrir l'avenir comme vous ne l'avez jamais vu ! » Avec la montée des tensions dans la région, nous pensons qu'il ferait mieux de modérer ses propos.");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour revenir...", passage142_Fragment_1);
        using (styleScope("hook", "h000014201"))
            yield return link("Cliquez pour revenir...", null, () => enchantHook("h000014201", HarloweEnchantCommand.Replace, passage142_Fragment_0));

        yield break;
