    IStoryThread passage147_Fragment_4()
    {
        using (styleScope("bold", true))
        {
            yield return text("Un investissement sournois");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Extrait d\'un journal intime - ");
            yield return text(Vars.busm);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("(suite)");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(macros1.either("Je pouvais distinctement voir des poils pousser dans la paume de sa main à mesure" +
            " qu\'il parlait.", "Il se pencha vers moi en murmurant grassement. Je pouvais presque sentir de la ra" +
            "ncune dans son haleine."));
        yield return text(" ");
        yield return text("« Investissez avec moi et oublions cette histoire de réhabilitation de l\'esprit. " +
            "Gardez bien en tête, ");
        using (styleScope("bold", true))
        {
            yield return text("vous n\'êtes pas obligé de payer maintenant");
        }
        yield return text(". Nous nous arrangerons plus tard pour le paiement, lorsque ");
        using (styleScope("bold", true))
        {
            yield return text("vous serez lassé");
        }
        yield return text(", j\'en suis sûr. »");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.busvp == 1)
        {
            yield return text("L\'homme sourit encore. « Bien sûr, essayons de nouveau. »");
            yield return lineBreak();
            yield return lineBreak();
        }
        yield return text("« ");
        using (styleScope("bold", true))
        {
            yield return text("Pour 1$");
        }
        yield return text(", je vous garantis que si j\'arrive à m\'implanter dans la région, je vous fournira" +
            "i un ");
        using (styleScope("bold", true))
        {
            yield return text("nouveau domestique");
        }
        yield return text(" ");
        yield return text("au début de chaque décennie. »");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.bnc < 2)
        {
            yield return text("« ");
            using (styleScope("bold", true))
            {
                yield return text("Pour 2$");
            }
            yield return text(", je vous garantis un investissement lucratif dans une main-d\'œuvre qualifiée. »");
