        yield return lineBreak();
        yield return text(@"J'ai omis un détail singulier qui a marqué cette journée d'inauguration. Alors que je retournais à mon carrosse, un vieil homme a remarqué mon air renfrogné et est venu m'aborder. Il était grand, habillé en noir de la tête aux pieds. Ses lèvres étaient rougeâtres, ses sourcils grisonnants, sa peau pâle, et sa moustache longue et blanche.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("« Vous ne croyez pas à ces foutaises de rééducation, n\'est-ce pas ? » me demanda-" +
            "t-il en tordant son nez aquilin. « Les Français comme ces cinglés de libéraux. A" +
            "idez-les une fois et ils ");
        using (styleScope("bold", true))
        {
            yield return text("augmenteront vos impôts");
        }
        yield return text(" ");
        yield return text("pour vous obliger à les aider encore. »");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("« Certaines personnes naissent pour travailler. Et quelques pauvres âmes égarées " +
            "viennent au monde avec des travers qu\'on ne peut guérir. Mais je suis persuadé q" +
            "ue tout le monde peut trouver sa place, et tout caractère peut être utile. »");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le vieil homme m\'invita à lui rendre visite dans sa nouvelle maison, en bordure d" +
            "e la ville, si jamais je pensais, comme lui, que ce Refuge pourrait servir plus " +
            "efficacement nos intérêts mutuels.");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage157_Fragment_1);
        using (styleScope("hook", "h000015701"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000015701", HarloweEnchantCommand.Replace, passage157_Fragment_0));

        yield return lineBreak();
        Vars.crpg = 0;
        yield break;
    }

