    // .............
    // #174: JailEvent1

    void passage174_Init()
    {
        this.Passages[@"JailEvent1"] = new StoryPassage(@"JailEvent1", new string[] { "Trad-FR", }, passage174_Main);
    }

    IStoryThread passage174_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("La fuite");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre expédiée par ");
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("(suite)");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"J'ai rencontré leur meneur hier, sous la contrainte je vous l'assure. J'étais là, au milieu des criminels et des sociopathes en camisole qui me malmenaient et me bousculaient sur les marches de la prison, ou de la Bimbeloterie comme ils l'appellent désormais.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.kill == "blacksmith")
        {
            yield return text(@"Un homme s'avança sous les hourras d'une foule de mécréants. Il était fort et hirsute, avait le teint rouge, une large mâchoire carrée et une barbe entrecoupée de profondes cicatrices sur ses joues. Il portait un épais tablier couvert de taches sombres dont une bretelle était déchirée à la base. À en juger de sa démarche assurée et exubérante, il semblait tirer de la fierté de sa crasse. Sa main gantée tenait un marteau dégoulinant lui aussi d'une substance rouge qui lui tachait les doigts.");
        }
        if (Vars.kill == "butcher")
        {
            yield return text(@"Une femme s'avança sous les hourras d'une foule de mécréants. Ses cheveux ébouriffés, d'un noir luisant, étaient coupés court, presque à la garçonne, avec des reflets de pétrole. Ils détouraient son visage anguleux et drapaient le cache-œil noir qui recouvrait son œil gauche. Elle portait un épais tablier, autrefois blanc, mais désormais couvert de tâches pourpres et d'éclaboussures d'un rouge plus frais sur la poitrine. De sa main gantée, elle brandissait un fendoir métallique, dont la lame était rouillée au niveau de la poignée et émoussée par de longues années d'usage.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("« On m\'appelle ");
        yield return text(Vars.warden);
        yield return text(". Ça commence à dater mais vous vous souvenez peut-être de ma famille et de la fa" +
            "çon dont elle a été détruite par les accusations hystériques des paysans du coin" +
            ". Eh bien nous, les déshérités, avons repris ce qui nous revenait de droit. ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text("a pris le contrôle de cette ville ! » ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("La horde hétéroclite rugit en signe d\'approbation. Ses membres se frappaient la p" +
            "oitrine et tapaient des objets métalliques entre eux. ");
        if (Vars.creature == 1)
        {
            if (Vars.exped == 0 || Vars.exped == "")
            {
                yield return text("Je remarquai une ombre à l\'intérieur de la bimbeloterie, j\'aperçus sa silhouette " +
            "difforme quelques instants devant l\'entrée avant qu\'elle ne disparaisse. Était-c" +
            "e la créature que j\'avais pourchassée ?");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("« Je vous ai fait amener ici parce que je pense que vous pouvez nous être utile. " +
            "Mais faites bien attention, ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text("exige la loyauté. » ");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "JailEvent1A", null);
        yield return lineBreak();
        yield break;
    }


