        yield return passage("journal1a");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les abords de l'Arène étaient généreusement décorés pour l'occasion : des drapeaux rouge sang flottaient sous l'arche de la gigantesque porte d'entrée, et un inextricable ensemble de tuyaux de cuivre crachait de la vapeur sous pression en sifflant. Dans un lourd grincement, les grandes portes en aluminium s'ouvrirent sur le sol craquelé de l'Arène. Les habitants dérangés de cette ville nous entouraient, mes cousins et moi, dans leurs étranges accoutrements faits d'un imposant mélange de cuir et de métal rouillé.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text("s\'assit au bout de l\'Arène sur un trône de cuivre dont la base était constituée d" +
            "\'un amas de débris métalliques.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Mes cousins et moi avions effectué tout ce qui nous avait été demandé. Il ne rest" +
            "ait plus qu\'une dernière obligation. Avant de quitter ce monde, je vais recouvri" +
            "r cette arène de sang et d\'huile. Que le combat commence !");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "BattlePreparation", null);
        yield return lineBreak();
        yield break;
    }


