    // .............
    // #182: Prologue-FOTU

    void passage182_Init()
    {
        this.Passages[@"Prologue-FOTU"] = new StoryPassage(@"Prologue-FOTU", new string[] { "Trad-FR", }, passage182_Main);
    }

    IStoryThread passage182_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Un petit mot pour ma sœur");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Roderick Tenderson - ");
            using (styleScope("italic", true))
            {
                yield return text("1932.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ces derniers mois, j'ai bien avancé dans mes recherches. Mes hôtes m'hébergent confortablement, et les repas copieusement servis me réchauffent le cœur et l'esprit. Bien que je sois très reconnaissant de leur hospitalité, je n'ai pas encore pu les en remercier directement. Le gardien m'assure qu'ils prolongent leurs vacances mais leur absence me met mal à l'aise. Nous avions un accord mais quelque chose me trouble, sans que je n'arrive à savoir de quoi il s'agit exactement.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Il semblerait que je souffre d'une xénophobie mineure, une sorte de peur de l'inconnu qui me pousse à surveiller les recoins sombres de ce domaine tout aussi impeccable que délabré. La nuit tombée, je crois entendre l'écho lointain d'un marteau, le métal frappant le métal, comme le grondement du tonnerre. Pourtant, lorsque je sors sur la terrasse en chemise de nuit, je ne suis accueilli que par le chant des cigales et le doux parfum des tulipes.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Pour ce qui nous concerne : vous trouverez dans le paquet accompagnant cette missive, une incroyable collection d'articles, de journaux et de lettres relatant l'illustre passé de ce domaine si particulier et de ses propriétaires. Leur richesse est impressionnante et je les ai arrangés de sorte à raconter une histoire vivante et hors du commun.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Je pense rentrer à Londres sous peu mais j'ai préféré poster cet envoi avant mon départ afin d'alléger mon fardeau. J'ai peur de ne plus faire preuve du même courage qu'autrefois. Si quelque chose devait m'arriver, je vous fais confiance pour diffuser cette lettre et la faire publier comme vous jugerez bon de le faire.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Comme toujours, je pense affectueusement à vous. Transmettez à Mère mes plus chal" +
            "eureuses salutations.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Roderick");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "FearoftheUnknownStart", null);
        yield return lineBreak();
        if (Vars.players == 2)
        {
            Vars.randomplayer = macros1.a(Vars.nameA, Vars.nameB);
        }
        if (Vars.players == 3)
        {
            Vars.randomplayer = macros1.a(Vars.nameA, Vars.nameB, Vars.nameC);
        }
        if (Vars.players == 4)
        {
            Vars.randomplayer = macros1.a(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
        }
        if (Vars.players == 5)
        {
            Vars.randomplayer = macros1.a(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
        }
        yield break;
    }


