    IStoryThread passage199_Main()
    {
        yield return text("Man sees the unfortunate wretches. It is most certainly unfair, but it is the way" +
            " the world works. He is basically Count Dracula.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("For me it is so much easier.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("He desires faithful servants, but they are so, well, not expendable.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The asylum is financially precarious. If they offer you an opportunity to invest," +
            " simply refuse and I will provide free labor for your troubles. Good help is dif" +
            "ficult to find, yes?");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Businessman offers to invest in privatization of the Asylum. If he can get contro" +
            "l of the system. Easily can double the occupancy. Cheap labor.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("This will result in a free Servant from Lost at the start of every round.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Description of home and meeting.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("\"It is so difficult these days to procure good servants, am I correct? There was " +
            "once a time where a man could provide lodging for one of the unfortunate wretche" +
            "s and he would be called a kind-hearted soul. Now there are far too many papers " +
            "to sign.\"");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("\"The Asylum is in a financially precarious position. If they offer you an opportu" +
            "nity to invest, simply refuse and I will provide free labor for your troubles.\"");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("(locks in the player as \"free labor\" if they refuse.)");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Draw a Compulsion card ");
            using (styleScope("italic", true))
            {
                yield return text("(do not move on the Sanity Track)");
            }
            yield return text(".");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Storybook token:");
        yield return lineBreak();
        yield return text("Asks the player for assistance in secret. Cure the visiting Count of his afflicti" +
            "on.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cure him");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("I understand that this will take some time to procure, but waiting is not somethi" +
            "ng to which I am unaccustomed. I will be here if you wish to talk of other busin" +
            "ess in the future.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Special Setup");
        }
        yield return lineBreak();
        yield return text("Return the Storybook token to the supply.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cure him by gifting him a C-Level Occult Experiment at the End of the Génération." +
            "");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Would you like to offer a cure to the Count for his affliction?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Yes. ");
        using (styleScope("italic", true))
        {
            yield return text("(You will donate a completed C-Level Occult Experiment.)");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("No. ");
        using (styleScope("italic", true))
        {
            yield return text("(You must choose this option if you do not have a completed C-Level Experiment.)");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cure Yes.");
        yield return lineBreak();
        yield return text("\"Thank you for what you have brought me. Upon being confronted with the reality o" +
            "f the situation, I must confess that the thought fills me with both trepidation " +
            "and comfort.\"");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Offers the BLESSING of STRIGOI. A Traumatisme card.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("2 Creepy at start. Your Self instead gains 3X the benefit of any Location in Town" +
            ". Your Self instead can perform any Estate Action 2X with one placement.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("2 Creepy at start. ");
