        yield return lineBreak();
        yield return text("(Count does not appear in the next Génération.)");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cure No.");
        yield return lineBreak();
        yield return text("\"Perhaps it is for the best. \"");
        yield return lineBreak();
        yield return text("(Count appears in the next Génération.)");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Count Mad Max");
        yield return lineBreak();
        yield return text("Appears at start to offer a free Servant to all.");
        yield return lineBreak();
        yield return text("Is well aware and leaves an ominous warning.");
        yield return lineBreak();
        yield return text("\"I caution you to not value their assistance too strongly. It is");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Count Asylum");
        yield return lineBreak();
        yield return text("Becomes the head doctor of the Asylum. Appears youthful and full of energy.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
