    // .............
    // #209: FOTU-End1

    void passage209_Init()
    {
        this.Passages[@"FOTU-End1"] = new StoryPassage(@"FOTU-End1", new string[] { "Trad-FR", }, passage209_Main);
    }

    IStoryThread passage209_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Englouti par les ténèbres");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Correspondance - ");
            yield return text(Vars.winner);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("25 juin 1926");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"J'ai l'impression de ne pas vous avoir écrit depuis des années. La ville dans lequel nous avons séjourné toutes ces années est bien silencieuse désormais. Ses remparts en ruine sont un cruel rappel de ce qui s'est passé ici, une sorte de métaphore de l'isolement nécrosant provoqué par la xénophobie. Je me rappelle encore de ces maudits remparts qui entravaient l'enthousiasme de ma jeunesse à chaque fois que je me rendais dans ce bourg triste et obscur. Un bourg qui ne pourra plus jamais être reconstruit après le passage de notre monstrueuse Expérience.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Et pourtant, l'indomptable résultat de nos efforts familiaux continue de me tourmenter ! Non, je ne peux plus perpétuer ce terrible héritage qui a provoqué la destruction de notre domaine et d'une ville toute entière. Mes camarades universitaires n'ont plus aucun respect pour moi. Ils se moquent ouvertement de moi lorsque je parle de mon lieu de naissance. Je ne peux leur en vouloir. J'espère seulement ne plus jamais avoir à retourner dans cette maudite bourgade. Comment ma famille a-t-elle pu entretenir une ligne de conduite aussi déviante ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Au moment où j\'écris ces quelques lignes, mon avocat a pris des dispositions pour" +
            " vendre la propriété. Je n\'aurai bientôt plus aucun lien avec ce domaine déchu e" +
            "t les horribles travaux qu\'il a abrités. Qu\'ils disparaissent à tout jamais.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Bruno Larochette");
        }
        yield break;
    }


    // .............
    // #210: FOTU-End2

    void passage210_Init()
    {
        this.Passages[@"FOTU-End2"] = new StoryPassage(@"FOTU-End2", new string[] { "Trad-FR", }, passage210_Main);
    }

    IStoryThread passage210_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Une ville modèle");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal intime : ");
            yield return text(Vars.winner);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("1er mars 1924.");
            }
            yield return text(" ");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Je me rends compte désormais à quel point j'ai pu me tromper. La véritable inspiration, la véritable science, l'art... tout ne vient que de l'isolement. L'isolement est un catalyseur. Le silence et la contemplation permettent de se concentrer sans la moindre source de distraction. Ce n'est qu'ainsi que l'on peut atteindre la perfection et l'illumination.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Les citoyens de ");
        yield return text(Vars.townname);
        yield return text(" ");
        yield return text("avaient raison. Ils ont pris la bonne décision. Les influences extérieures ne fai" +
            "saient que nous distraire et nous polluer l\'esprit.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Tout le monde devrait être autonome et ambitieux. Les sciences sont instinctives." +
            " Le génie ne s\'apprend pas à l\'université. Personne ne se souvient de ceux qui f" +
            "ont briller les autres. Non.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Tant mieux si le reste du monde n'est pas au courant des travaux de me famille, cela fait partie de mon plan. Je n'en serai que plus efficace, je pourrai me concentrer tranquillement sur mes recherches, à l'abri dans mon laboratoire. Mais bientôt, je sortirai de mon cocon scientifique pour resplendir comme jamais, et le monde tremblera à mes pieds !");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Bruno Larochette");
        }
        yield break;
    }


