            yield return text("Journal intime : ");
            using (styleScope("italic", true))
            {
                yield return text("nom illisible - ");
                yield return passage("date1a");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(macros1.either(@"Journée de vérifications : je portais mon tout dernier pardessus mais je n'ai même pas eu droit au moindre compliment des officiers réprobateurs qui surveillaient le perron. Au moins, la sécurité a été assez laxiste pour me laisser entrer dans le bureau gouvernemental délabré sans me faire subir de fouille corporelle.", @"Après-midi lugubre - impression renforcée par l'affreux brouillard qui enveloppait la ville dans la grisaille. Lorsque je suis arrivé à l'Hôtel de Ville pour les vérifications réglementaires, j'ai constaté, non sans un certain dédain, que le seul gardien, habillé d'un uniforme du XVIIIe siècle récemment rapiécé, était en train de dormir devant la grande double porte en bois. J'ai décidé d'entrer sans le déranger afin d'éviter de perdre plus de temps avec ces formalités."));
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
