    // #212: IsoIdentification

    void passage212_Init()
    {
        this.Passages[@"IsoIdentification"] = new StoryPassage(@"IsoIdentification", new string[] { "Trad-FR", }, passage212_Main);
    }

    IStoryThread passage212_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Vérifications effectuées");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal intime - ");
            yield return text(Vars.tempid);
            yield return text(" ");
            yield return text("- ");
            yield return passage("date1a");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(macros1.either("Miséreux. Regrettable. Déplorable. L\'Hôtel de Ville était envahi de toiles d\'arai" +
            "gnées, ses murs étaient fissurés et longés de vieux bancs moisis. Le bureau décr" +
            "épit dans lequel je devais confirmer mon existence n\'était pas mieux.", @"Même pas un bonjour. Aucune reconnaissance alors que je me soumets contre tous mes principes à cette occupation oppressante. Pour seule forme de salutation, je ne reçus que le grognement désintéressé d'un juriste qui trainait dans les parages, habillé d'un costume guindé. Un employé m'invita à m'asseoir d'un geste de la main, et il s'écoula une bonne heure avant que la personne censée procéder aux vérifications ne me reçoive."));
        yield return lineBreak();
        yield return lineBreak();
        yield return text(macros1.either("Tel un chien galeux, on me congédia sommairement après un bref coup d\'œil à mes p" +
            "apiers et un long interrogatoire. L\'officier en charge semblait moins se soucier" +
            " de la loi et des formalités qui m\'amenaient que de me dévisager avec insistance" +
            ".", @"L'interrogatoire dura jusqu'en début de soirée. La personne en charge de mon dossier en a manifestement profité pour se défouler et évacuer ses frustrations sur moi. Lorsque mes réponses étaient adéquates et mesurées, le questionnement devenait encore plus agressif. M'a-t-elle pris pour quelque imbécile ?"));
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Au bout d'un long moment, mon dossier a été péniblement approuvé. J'ai rassemblé mes papiers et mes esprits, et j'ai rapidement rejoint mon cab. Les chevaux se sont mis à piétiner en me voyant approcher, comme s'ils étaient eux aussi impatients de quitter ce misérable endroit.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h00257"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h00257", HarloweEnchantCommand.Replace, passage212_Fragment_0));
        yield return lineBreak();
        yield break;
    }

