    IStoryThread passage213_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Des résultats attendus et dévastateurs");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal intime - ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(" ");
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("15 Mars 1912.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.ex == "chem")
        {
            yield return text("Relevé d\'Expérience - Le tissu qu\'on ne peut pas tacher : ");
            yield return lineBreak();
            yield return text(@"Bien qu'apparemment inoffensif, notre tissu intachable présente d'autres caractéristiques impressionnantes. Parmi les effets secondaires notables, il semblerait qu'il repousse toute source de tache avec une puissance et une promptitude hors du commun. Lorsque nous l'avons offert à la mairie pour remplacer le drapeau de la ville, notre belle étoffe s'est brutalement mise à virevolter en claquant sauvagement dans les airs, ravageant le bureau du maire. Nous avons fui l'Hôtel de Ville et nous avons assisté, dans un mélange d'amusement contenu et de terreur, à la destruction totale du bâtiment par notre expérience en à peine quelques secondes.");
        }
        if (Vars.ex == "eng")
        {
            yield return text("Relevé d\'Expérience - Un domestique robotisé qui fait la cuisine avec des lasers " +
            ": ");
            yield return lineBreak();
            yield return text(@"Sans doute une mauvaise idée dès le début, et manifestement pas notre plus belle réussite, le robot majordome s'est presque immédiatement mis à tirer des lasers en tous sens, sans aucune retenue. Notre démonstration à l'Hôtel de Ville a tourné court et nous avons tous rapidement évacué afin de nous mettre à l'abri. Nous avons pu ainsi observer de loin le chaos évitable que nous venions de créer. L'Hôtel de Ville a été englouti par les flammes en quelques minutes. Terrifiant, vraiment.");
        }
        if (Vars.ex == "bio")
        {
            yield return text("Relevé d\'Expérience - Injection d\'hormones et de radium à un gorille agité : ");
            yield return lineBreak();
            yield return text(@"La cage dans laquelle nous présentions notre grand primate à l'Hôtel de Ville était tristement inadaptée, et il suffit du moindre des stimuli pour qu'il ne défonçât violemment sa geôle au tout début de notre exhibition. Maculée d'une quantité dérangeante de sang et de viscères en quelques secondes, notre inéluctable erreur détruisit la pièce et tout ce qui s'y trouvait comme une tornade de fourrure café et argentée. Nous quittâmes prestement les lieux afin d'observer à distance la pluie d'os brisés qui s'abattait telle la grêle sur les rues voisines.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Notre téméraire expérience continua son parcours destructeur jusqu\'à ce que nous " +
            "la maîtrisions avec un antidote préparé à la hâte.");
