            yield return passage("letter1a");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Plus les jours passent, plus je sens les abominables obsessions de mes parents rejaillir sur mes activités quotidiennes. Bien que les villageois se montrent courtois et sensibilisés aux maladies mentales, j'ai de plus en plus de mal à résister à l'appel de cet abyme qui pourrait bien représenter notre héritage familial ! ");
