            yield return lineBreak();
            yield return passage("letter1a");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"La résurgence du délire paranoïaque au sein de la population rurale rend particulièrement difficile la vie de tous ceux qui s'intéressent aux sciences. Toutefois, puisque l'hystérie générale conduit la plupart des habitants de la région, terrorisés par la moindre ombre qui passerait devant leurs fenêtres, à s'enfermer dans leurs maisons grisâtres à la tombée de la nuit, j'ose raisonnablement espérer que mes nouvelles obsessions passeront inaperçues dans ce paysage macabre.");
            yield return lineBreak();
            yield return lineBreak();
        }
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage214_Fragment_1);
        using (styleScope("hook", "h000021401"))
