    IStoryThread passage237_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Le monde a changé");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre expédiée par ");
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("(suite)");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Ainsi, ma présence est toujours tolérée, et le sera tant que je serai utile. ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text(@"exige que je rende hommage à sa gloire mais cette commande forcée est aussi une formidable opportunité d'explorer toutes les possibilités scientifiques sans les contraintes du milieu universitaire ou le jugement du public. Chaque fois que je me rends en ville, j'assiste à des scènes qui restent figées dans ma mémoire comme du goudron sous les ongles.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Dès que mes domestiques arrivent en ville, ils sont agressés par ces gredins et ramenés au domaine sans ménagement. Mais le caractère et l'apparence de mon fidèle assistant lui permettent de se fondre parfaitement parmi la foule, lui permettant par la même occasion de jouir d'une certaine liberté.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Peut-être que cette situation évoluera avec le temps, mais le monde dans lequel n" +
            "ous vivons a été chamboulé, et il va bien falloir s\'adapter.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Nouvelle règle");
        }
        yield return lineBreak();
        yield return text("Vous n\'avez pas le droit de placer vos pions Domestique/Épouse en Ville tant que " +
            "vous n\'avez pas ");
        using (styleScope("bold", true))
        {
            yield return text("atteint ou dépassé le marqueur ");
            yield return text("<sprite=\"AngryMob_Icon\" index=0>");
        }
        yield return text(".");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Votre Assistant peut être placé en Ville.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "JailEvent1c", null);
        yield return lineBreak();
        yield break;
    }


