    IStoryThread passage246_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Un investissement douteux");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Extrait d\'un journal intime - ");
            yield return text(Vars.busm);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return passage("date1a");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(macros1.either(@"Le Comte et ce qui semblait être un groupe d'invités aux manières très semblables, amicales, mais tout aussi distantes, m'ont invité à m'approcher d'une somptueuse table de réception dressée comme si ma présence était attendue pour le repas. Je dinai de généreuses assiettes de faisan à la crème, de pudding noir et d'ostropel, accompagnées d'un bon verre d'eau-de-vie de prune. À la fin du repas, malgré une nourriture riche et variée, je fus surpris d'avoir encore faim.", @"L'assistant du Comte me conduit jusqu'à son bureau, où le gentilhomme se détendait dans un fauteuil en sirotant un plein verre d'un vin rouge charpenté. Il m'invita à m'asseoir et nous discutâmes de longues minutes. Je pris le temps d'observer les magnifiques étagères en acajou qui entouraient la pièce, bardées de livres si neufs que leurs dos n'étaient pas craquelés."));
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Le Comte aborda enfin le sujet qui nous réunissait : « Je suis fidèle aux traditions. Contrairement aux trompeuses philosophies modernes, si vite passées de mode, je pense que l'investissement ne devrait pas être basé uniquement sur la bonté et de vagues promesses, mais un accord ferme et mutuellement profitable. J'y gagne et vous y gagnez. »");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Il me glissa qu\'il avait une offre à me proposer, qui m\'intriguerait à coup sûr.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h00283"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h00283", HarloweEnchantCommand.Replace, passage246_Fragment_0));
        yield break;
    }

