            yield return lineBreak();
            yield return text(@"Depuis ce jour, je me sens incroyablement bien : une santé de fer et une volonté à toute épreuve. Je suis également plus affable, et lorsque je parle, les gens m'écoutent plus attentivement. Mon accent est un peu plus marqué et j'ai du mal à prononcer les S correctement.");
