    IStoryThread passage258_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Aider les Institutions");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return passage("letter1a");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Il était bien naturel que mes contributions au Refuge ne se limitent pas à leur a" +
            "spect financier. Vous êtes sans doute lassée de m\'entendre le répéter, mais leur" +
            "s méthodes sont trop timides et leur efficacité limitée.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les responsables du Refuge ont toujours été faibles. Leur ligne directrice, qui oscille entre l'eugénisme et l'hérédité de facteurs dominants, leur a valu de nombreuses critiques de toutes parts. Je reste sceptique quant à leurs nouvelles idées, mais sans doute suis-je toujours sceptique. Sommes-nous tous si irrémédiablement soumis au destin que nous réserve Dieu ou la nature ? Ne pourrait-on pas suivre notre propre volonté et cultiver de meilleures valeurs ? Devons-nous tous baisser les bras et nous morfondre sur des canapés molletonnés en déplorant notre héritage mendélien.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Je pense qu'il est grand temps de mettre en place un nouveau programme, ambitieux et innovant. J'ai pris rendez-vous avec le directeur du Refuge. Pas la peine de me souhaiter bonne chance, je sais me montrer très persuasif. Le changement se profile à l'horizon.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "LiberalEvent3b", null);
        yield return lineBreak();
        yield break;
    }


