        yield return text("Le Refuge a annoncé de grands bouleversements dans sa politique de réhabilitation" +
            ", afin d\'intégrer les toutes dernières avancées dans le traitement des troubles " +
            "aliénistes. ");
        if (Vars.mentype == "Ingénierie")
        {
            yield return text(@"La nouvelle aile de l'établissement accueille les équipements sophistiqués utilisés pour cette nouvelle thérapie. Les patients atteints de divers degrés de démence sont soigneusement attachés à leur lit tandis que des électrochocs leur sont délivrés dans des zones bien précises du cerveau.");
        }
        if (Vars.mentype == "Chimie")
        {
            yield return text(@"Grâce aux récentes découvertes en matières d'opiacés, les docteurs administrent de puissants sédatifs qui permettent de calmer les patients, et d'éviter des réflexes inappropriés. Le traitement mélangeant saignées et ingestion de purgatifs permet d'évacuer les tendances psychotiques du corps du sujet.");
        }
        if (Vars.mentype == "Biologie")
        {
            yield return text(@"Un nouveau bloc chirurgical a été installé afin que les spécialistes de passage, tout comme le public, puissent découvrir les nouvelles procédures pendant leur mise au point. Elles rendent aux malades leur calme et leurs facultés en retirant les tissus affectés du cerveau ou en modifiant leur pression crânienne.");
        }
        if (Vars.mentype == "Occultisme")
        {
            yield return text(@"Bien que la direction garde le silence sur les détails de la procédure, un évêque du diocèse local s'est installé sur place pour offrir ses bénédictions à tous ceux qui se seraient laissés tenter par le Malin. Les patients sont protégés de toute forme d'excitation et profitent d'une bonne ""cure de repos"" et d'un traitement tonique à base d'herbes et de racines de la région.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Bien que ces méthodes soient encore l\'objet de nombreuses critiques, l\'organisati" +
            "on progressiste souhaite mettre ce changement en avant afin de prouver que ");
        yield return text(Vars.townname);
        yield return text(" ");
        yield return text("reste à la pointe du soin psychiatrique moderne en Transylvanie.");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage261_Fragment_1);
        using (styleScope("hook", "h000026101"))
