            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("Juillet 1926.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Le sujet ne présente aucun signe d'antécédents paranoïaques. Les épisodes schizophréniques ont cessé au cours du suivi. Le programme d'exercice préconisé comprend plusieurs promenades sans surveillance dans le périmètre du parc. Bredouille régulièrement seul ou avec les gens qui l'entourent d'un « travail inachevé ». Léger inconfort post-opératoire. 20 gouttes de teinture d'opium par jour.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Comportement : calme, distant. Rien d\'atypique pour ce type de rééducation.");
        yield return lineBreak();
        yield return lineBreak();
