        yield return lineBreak();
        yield return text("Évaluation du médecin : l\'ablation du lobe frontal est considérée comme un succès" +
            ". Maintenir le protocole de suivi continu. Réévaluer la possibilité de soins à d" +
            "omicile dans six mois.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
