    }

    IStoryThread passage263_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Prise en charge");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre expédiée par ");
            if (Vars.curecount == "yes")
            {
                yield return text("Vlad III Dracula");
            }
            else
            {
                yield return text(Vars.winner);
            }
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("12 novembre 1924.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("J\'espère que vous recevez cette lettre en pleine forme. Les nouvelles qui me vien" +
            "nent de Bucarest sont bonnes, paix et fraîcheur de saison. Ainsi, je vous prie d" +
            "e me pardonner si je fais l\'impasse sur les frivolités pour aborder directement " +
            "les affaires.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("L\'institution à ");
        yield return text(Vars.townname);
        yield return text(" ");
        yield return text(@"est un incroyable succès. Un flot continu de patients souffrant de folie ou de bouffées délirantes nous est envoyé de toutes les régions du pays. Pourtant, les autorités se demandent encore comment nous pouvons faire preuve d'une telle efficacité en fonctionnant avec un budget aussi faible. Il me semble que c'est dû en bonne part au ");
        using (styleScope("bold", true))
        {
            yield return text("Programme ");
            yield return text(Vars.menname);
        }
        yield return text(" ");
        yield return text("qui est désormais reconnu dans toute l\'Europe pour ses méthodes originales. Le co" +
            "mportement des patients impliqués dans le programme s\'est considérablement améli" +
            "oré.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Voici donc la raison de cette missive : je me dois de renouveler ma demande, nous avons besoin de nouveaux patients à traiter. Notre ratio de réussite frôle les 100%, nous avons donc plusieurs places disponibles et nous avons urgemment besoin de nouvelles entrées.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les préoccupations que vous exprimiez dans votre dernière lettre sont légitimes. Comme sont suivis les patients après leur sortie ? Comment évaluons-nous leurs progrès en société ? Comment prouver que le traitement n'a pas échoué et que nous n'avons pas utilisé leurs corps pour des expériences ? Pourquoi l'enveloppe de ma précédente lettre était-elle tachée de sang ? Toutes ces questions sont importantes.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Mais je vous le demande : pourquoi vouloir à tout prix remettre en cause nos ");
        using (styleScope("bold", true))
        {
            yield return text("résultats");
        }
        yield return text(" ");
        yield return text("?");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Bruno Larochette");
        }
        yield break;
    }


