            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Fort heureusement, lorsque je suis arrivé à l'Hôtel de Ville pour remettre mon paiement en personne (car oui, en plus de nous imposer cette nouvelle taxe, ils exigent que je me déplace pour leur remettre en main propre), un grand gentilhomme portant un costume bien coupé, un large chapeau et une écharpe couvrant le bas de son visage, s'est avancé vers moi.");
        yield return lineBreak();
