    // #269: LiberalReplace

    void passage269_Init()
    {
        this.Passages[@"LiberalReplace"] = new StoryPassage(@"LiberalReplace", new string[] { "Trad-FR", }, passage269_Main);
    }

    IStoryThread passage269_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Soutien et compréhension");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre expédiée par ");
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("19 mai 1892. Roumanie.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("L\'évolution de la ville s\'est avérée tendre régulièrement vers l\'apaisement. Cela" +
            " repose sans doute en partie sur la paix de l\'esprit que de nombreux villageois " +
            "ont trouvé au Refuge.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"L'institution n'a pas seulement agrandi ses bâtiments, elle a également élargi son influence sur les cœurs et les esprits des habitants. Ce n'était pas très difficile pour le premier si vous voulez mon avis. Toutefois, il semblerait que tout soit fait correctement. ");
        if (Vars.jail == 2)
        {
            yield return text("J\'ai entendu dire qu\'un certain Dr Vlad Dracula avait pris la direction du Progra" +
            "mme du Refuge. Il a plutôt bonne réputation.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"La population a même tellement accepté cette idée de réhabilitation mentale qu'elle serait d'accord pour envoyer tout le monde passer un examen général régulier. J'entends déjà les moqueries de nos collègues phrénologues. Mais cela m'est plutôt rassurant quant aux conséquences de nos expériences sur la population. Leurs effets resteront limités même si l'on dépasse les limites du raisonnable.");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage269_Fragment_1);
        using (styleScope("hook", "h000026901"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000026901", HarloweEnchantCommand.Replace, passage269_Fragment_0));

        yield return lineBreak();
        yield break;
    }

