    IStoryThread passage271_Main()
    {
        if (Vars.jail == 1)
        {
            using (styleScope("bold", true))
            {
                yield return text("Héritage miséricordieux");
            }
            yield return lineBreak();
            yield return lineBreak();
            using (styleScope("bold", true))
            {
                yield return text("Lettre expédiée par ");
                yield return text(Vars.randomname);
                yield return text("- ");
                using (styleScope("italic", true))
                {
                    yield return text("(suite)");
                }
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text(Vars.warden);
            yield return text("nous a offert un passe-droit en souvenir de nos ancêtres et de ");
            using (styleScope("bold", true))
            {
                yield return text("la volonté de notre famille de financer le Refuge");
            }
            yield return text(". Nous continuerons de bénéficier de certains avantages lorsque nous nous rendron" +
            "s à la Bimbeloterie.");
            yield return lineBreak();
            yield return lineBreak();
            using (styleScope("bold", true))
            {
                yield return text("Règle pour ");
                yield return text(Vars.asymlump);
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Lorsqu\'un joueur possédant la tuile ");
            yield return text(Vars.asymlump);
            yield return text("se place sur la Bimbeloterie, il peut activer sa capacité.");
            yield return lineBreak();
            yield return lineBreak();
            yield return link("Cliquez pour continuer...", "EndtotheCount", null);
        }
        if (Vars.jail == 2)
        {
            if (Vars.asylumcount >= 1)
            {
                using (styleScope("bold", true))
                {
                    yield return text("Sacrifice Exigé");
                }
                yield return lineBreak();
                yield return lineBreak();
                using (styleScope("bold", true))
