                    yield return text("- ");
                    using (styleScope("italic", true))
                    {
                        yield return text("(suite)");
                    }
                }
                yield return lineBreak();
                yield return lineBreak();
                yield return text("Que pourrais-je faire de cette extension de mon Domaine inutile depuis la dispari" +
            "tion du Refuge ?  Ce serait sûrement un gaspillage de temps et d\'énergie que de " +
            "rénover ce bâtiment. Mieux vaut s\'en débarrasser que de le laisser tomber en rui" +
            "nes.");
                //yield return enchantIntoLink("Cliquez pour continuer...", passage271_Fragment_1);
                using (styleScope("hook", "h000027101"))
                    yield return link("Cliquez pour continuer...", null, () => enchantHook("h000027101", HarloweEnchantCommand.Replace, passage271_Fragment_0));

            }
            else
            {
                yield return abort(goToPassage: "EndtotheCount");
            }
        }
        yield return lineBreak();
        yield break;
    }

