    // .............
    // #275: FOTU-End5

    void passage275_Init()
    {
        this.Passages[@"FOTU-End5"] = new StoryPassage(@"FOTU-End5", new string[] { "Trad-FR", }, passage275_Main);
    }

    IStoryThread passage275_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("De la poussière pour les braves");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal intime - ");
            yield return text(Vars.winner);
            yield return text(" ");
            yield return text("- 16 août 1929");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Dimanche, j\'ai encore fait ce merveilleux rêve. Il m\'insuffle à chaque fois une é" +
            "nergie considérable, au point que je pourrais le revivre chaque nuit jusqu\'à la " +
            "fin de mes jours avec le plus grand des plaisirs.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("J\'observe fièrement ");
        if (Vars.winner == Vars.nameA)
        {
            string s = Vars.warriorA.ToString();
            yield return text(s.Replace("_1", ""));
            //yield return text(Vars.warriorA);
        }
        if (Vars.winner == Vars.nameB)
        {
            string sb = Vars.warriorB.ToString();
            yield return text(sb.Replace("_2", ""));
            //yield return text(Vars.warriorB);
        }
        if (Vars.winner == Vars.nameC)
        {
            string sc = Vars.warriorC.ToString();
            yield return text(sc.Replace("_3", ""));
            //yield return text(Vars.warriorC);
        }
        if (Vars.winner == Vars.nameD)
        {
            string sd = Vars.warriorD.ToString();
            yield return text(sd.Replace("_4", ""));
            //yield return text(Vars.warriorD);
        }
        if (Vars.winner == Vars.nameE)
        {
            string se = Vars.warriorE.ToString();
            yield return text(se.Replace("_5", ""));
            //yield return text(Vars.warriorE);
        }
        yield return text(", notre création familiale, décapiter ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text(@"et soulever sa tête coupée tel un trophée, dans une atmosphère cathartique. Je ressens la chaleur intense de l'huile brûlante, j'entends le sifflement de la vapeur et je sens l'odeur du métal rouillé. L'Arène bondée m'acclame alors que j'ai vaincu son guide, arraché à son trône de pacotille et jeté, sans vie, au milieu de cette fosse poussiéreuse. Son corps baigne dans son sang, noir et épais comme de l'huile de moteur.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ces images apparaissent encore dans mon esprit comme des flashs, alors même que j'écris ces quelques lignes. Mon dernier acte de bravoure, sans doute. Mais à quoi servirait-il se renverser un tyran au pouvoir si limité ? Autant d'efforts pour essayer de changer le monde sur à peine plus d'un kilomètre carré ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les détenus sont passés à autre chose. La ville est un champ de ruines désert, sans la moindre végétation, un cloaque moisi de cendre, de rouille et de boue. Parfois, j'ai l'impression que mon esprit est dans le même état. Le sentiment de paix intérieure ne suffit pas à combler l'absence de but en moi. ");
        if (Vars.creature == 2)
        {
            yield return text("Une vieille connaissance me rend visite de temps en temps. Il s\'agit d\'un proche " +
            "de la famille au visage flétri, qu\'il garde caché derrière une grande écharpe no" +
            "ire.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Quel gâchis ! Quel terrible investissement ! Je ne peux plus qu\'espérer que mes d" +
            "escendants quitteront ces terres désolées et sauront se forger une autre destiné" +
            "e.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Bruno Larochette");
        }
        yield return lineBreak();
        yield break;
    }


    // .............
    // #276: FOTU-End6

    void passage276_Init()
    {
        this.Passages[@"FOTU-End6"] = new StoryPassage(@"FOTU-End6", new string[] { "Trad-FR", }, passage276_Main);
    }

    IStoryThread passage276_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Notre guide éternel");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre expédiée par ");
            yield return text(Vars.winner);
            yield return text(" ");
            yield return text("- 5 mai 1925");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les coutumes transylvaniennes sont encore plus surprenantes que dans mes souvenirs. J'avais de vagues souvenirs de ma jeunesse, de l'enseignement que je suivais à la maison, loin du village embrumé niché au fond de la vallée. Mais je n'aurais jamais deviné la véritable raison de cet éloignement.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("J\'ai établi une alliance avec les autorités locales, sur la base de la bonne volo" +
            "nté de mes parents. Elles ont élu démocratiquement ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text("à leur tête, et m\'ont promis de me fournir de la main d\'œuvre et des matériaux po" +
            "ur poursuivre mes expérimentations. Je comprendrais aisément votre appréhension " +
            "naturelle face à ce surnom, « ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text("», mais je vous assure que son titre lui vient du dialecte local et qu\'il fait pa" +
            "rtie du folklore. En parallèle, une grande arène a été érigée, à l\'intérieur mêm" +
            "e de la ville, où une forme de combat particulièrement agressive est pratiquée.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"À l'arrivée, je trouve la ville surprenamment accueillante et bienveillante envers la science et le progrès, ce qui s'accorde plutôt bien à mes besoins, comme vous pouvez l'imaginer. J'ai même prévu un rendez-vous ce weekend avec un Comte du coin. Il prétend être un ami de la famille qui voudrait remettre un pied dans l'économie locale.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Bruno Larochette");
        }
        yield return lineBreak();
        yield break;
    }


    // .............
    // #277: FOTU-End3

    void passage277_Init()
    {
        this.Passages[@"FOTU-End3"] = new StoryPassage(@"FOTU-End3", new string[] { "Trad-FR", }, passage277_Main);
    }

    IStoryThread passage277_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Un nouveau printemps");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Correspondance - ");
            yield return text(Vars.winner);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("14 juin 1925");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Si vous pouvez sentir l'odeur du thé et des viennoiseries sur la lettre que vous tenez entre les mains, c'est parce que je l'ai écrite dans l'une de mes boutiques préférées de la rue principale. Les bruits de pas et le ronron métallique des automobiles sur le béton font vagabonder mon âme. On y sert un thé incroyablement bon. C'en est presque désagréablement génial de disposer de ce genre de biens par ici de nos jours. C'est clairement l'un des avantages des marchands ambulants qui assurent notre approvisionnement en produits fins. ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Il semble que le village lugubre que nous avons connu ait laissé la place à une ville florissante. Les membres de ma famille ont peut-être commis quelques erreurs, mais leur bienveillance (qui me surprend moi-même) a su convaincre et apaiser les peurs au sein de la population. Aujourd'hui, je peux travailler sur mes prochaines expériences en public sans que l'on me regarde comme une bête de foire. Et c'est plutôt agréable.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Certains sont même prêts à s'investir dans mes ""activités excentriques"", comme ils les appellent. Leur bêtise me surprendra toujours. Je prendrai plaisir à exploiter une telle ignorance. Mais j'essayerai de rester raisonnable, ce calme printanier ne couvrirait pas leurs hurlements.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Quoi qu\'il en soit, transmettez à Mère mes plus chaleureuses salutations, et reve" +
            "nez me voir bientôt.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Bien à vous.");
        yield return lineBreak();
        yield return text(Vars.winner);
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Bruno Larochette");
        }
        yield return lineBreak();
        yield break;
    }


    // .............
    // #278: FOTU-End4

    void passage278_Init()
    {
        this.Passages[@"FOTU-End4"] = new StoryPassage(@"FOTU-End4", new string[] { "Trad-FR", }, passage278_Main);
    }

    IStoryThread passage278_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("La colère de la foule");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre expédiée par ");
            yield return text(Vars.winner);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("4 janvier 1924");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cela a fini par se produire. Ils ont tout détruit. La populace, brandissant des torches et des fourches, a abattu mes clôtures avant de ravager le domaine, réduisant en cendres tout le travail de mes parents. Ces débiles ont eu l'audace de débarquer sans prévenir. Si je n'avais pas entendu les chiens éviscérer plusieurs d'entre eux, j'aurais sans doute moi aussi succombé aux flammes.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les terres ne sont plus qu'un champ de ruines recouvert de cendre, vaste paysage morne et gris. Mes demandes au gouverneur ont été accueillies dans l'indifférence et la moquerie. Il est évident que je ne recevrai aucun dédommagement pécunier pour les préjudices subis lors de cette émeute. Devrai-je éternellement affronter les conséquences des péchés de mon père ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Qu\'importe ! Ont-ils déjà perdu quelque chose ou quelqu\'un ? Moi, j\'ai tout perdu" +
            ". L\'intégralité de mon héritage familial a disparu dans les flammes. Ils nous ch" +
            "assent comme si nous étions des étrangers. Des étrangers sans le sou.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Mais ce n\'est pas fini. Je me vengerai. Ce misérable village regrettera le jour o" +
            "ù il a mis ");
        yield return text(Vars.winner);
        yield return text(", quatrième du nom, en colère !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Aussi, si vous aviez l\'amabilité de m\'accorder un petit prêt, je serais d\'autant " +
            "plus vite en position d\'exercer ladite vengeance.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Bruno Larochette");
        }
        yield return lineBreak();
        yield break;
    }


