    IStoryThread passage283_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Une vie à l\'écart");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Lettre expédiée par ");
            yield return text(Vars.tempid);
            yield return text(" ");
            yield return text("- ");
            yield return passage("date1a");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(macros1.either("Il n\'y avait personne pour m\'accueillir ce jour-là. Ainsi soit-il. Cela ne faisai" +
            "t pas partie des objectifs que je m\'étais fixés. Au contraire, j\'en avais moi-mê" +
            "me décidé. Une question qui m\'a longtemps pesé, au plus profond de mon être.", "Bien que l\'heure du rendez-vous fut arrivée, il ne se passa rien de particulier. " +
            "Je me perdis dans mes pensées une bonne partie de la journée. Quelque chose que " +
            "j\'aurais dû faire depuis longtemps."));
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Et j'atteignis une forme de croisement dans ma tête, un point où la désarroi de mon existence était étalé devant moi. Je pouvais continuer sur la voie de mon obsession chevillée au corps, ou suivre un nouveau chemin sur un coup de tête, sans contraintes, sous l'impulsion de mes propres envies. Quel que soit mon choix, je savais déjà que j'aurais besoin d'aller tout au bout de ce chemin.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Je choisis :");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return link("de garder mon Obsession.", "Gen3Token2a", null);
        yield return text(" ");
        using (styleScope("italic", true))
        {
            yield return text("(Vous gagnerez ");
            using (styleScope("bold", true))
            {
                yield return text("4 PV");
            }
            yield return text(" ");
            yield return text("supplémentaires si vous avez complété votre Obsession ou perdrez ");
            using (styleScope("bold", true))
            {
                yield return text("4 PV");
            }
            yield return text(" ");
            yield return text("si vous n\'y parvenez pas. Vous ");
            using (styleScope("bold", true))
            {
                yield return text("devez");
            }
            yield return text(" ");
            yield return text("choisir cette option si votre Obsession est déjà complétée.)");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("OU");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("une nouvelle voie.", "Gen3Token2b", null);
        yield return text(" ");
        using (styleScope("italic", true))
        {
            yield return text("(Vous gagnerez ");
            using (styleScope("bold", true))
            {
                yield return text("4 Compulsions");
            }
            yield return text(" ");
            yield return text("et vous défausserez votre Obsession.)");
        }
        yield return lineBreak();
        yield break;
    }


