    IStoryThread passage289_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Prise de contrôle par la force");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return passage("letter1a");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Si vous recevez cette lettre, je vous conjure de reporter indéfiniment toute visi" +
            "te que vous auriez prévue dans cette ville maudite ! Les fous ont littéralement " +
            "pris le contrôle du Refuge.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("C\'est le chaos ! Le chaos le plus total. Il n\'y a pas d\'autre façon de décrire la" +
            " révolte qui s\'ensuivit et qui a conduit tous les habitants à fuir ");
        yield return text(Vars.townname);
        yield return text(@". Les détenus, ulcérés par leurs conditions de détention déplorables, ont succombé à la folie la plus profonde et n'ont laissé qu'un paysage ravagé dans leur sillage. Ils ont pris le contrôle de ce petit village bucolique et l'ont transformé en un champ de ruines rouillées. J'ai été trop ambitieux ! J'ai condamné cette ville à un destin apocalyptique ! ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Aujourd'hui encore, les rivières sont rouges de sang et de rouille. Comment ai-je pu me tromper à ce point, moi qui pensais que cette entreprise d'exploitation me permettrait d'achever mes travaux ? Devrai-je subir les conséquences de l'orgueil familial jusqu'à la fin de mes jours ?");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage289_Fragment_1);
        using (styleScope("hook", "h000028901"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000028901", HarloweEnchantCommand.Replace, passage289_Fragment_0));

        yield return lineBreak();
        yield break;
    }

