    // #290: PrivateReward1

    void passage290_Init()
    {
        this.Passages[@"PrivateReward1"] = new StoryPassage(@"PrivateReward1", new string[] { "revised", "Trad-FR", }, passage290_Main);
    }

    IStoryThread passage290_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Résidus de Décharge");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal intime : ");
            yield return text(Vars.tempname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return passage("date1a");
            }
        }
        yield return lineBreak();
        Vars.creepcount = int.Parse(Vars.creepcount) + 1;
        Vars.pripg = 1;
        yield return lineBreak();
        yield return lineBreak();
        yield return text("« Quel plaisir de voir âme ainsi mise à nu » me dit ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text(@"en regardant dehors par une fenêtre du grand hall jonché de débris. L'imposant portail en fer de l'entrée avait été arraché du béton et abandonné tel quel, exposé aux éléments. Il projetait une ombre torturée sur le sol en pierre. « Je constate que vous êtes un monstre au fond de vous. Et on ne devrait jamais reprocher à quelqu'un de suivre ses instincts naturels. »");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("J\'ai été sidéré par cette insinuation mais comme ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text("avait soulevé ");
        yield return text("{");
        yield return lineBreak();
        if (Vars.warden == "La bouchère")
        {
            yield return text("son fendoir et qu\'elle le pointait dans ma direction, j\'ai préféré garder mon obj" +
            "ection pour moi. Elle reprit.");
        }
        yield return lineBreak();
        if (Vars.warden == "Le Ravageur")
        {
            yield return text("son marteau et frappait la paume de sa main, j\'ai préféré garder le silence. Il r" +
            "eprit.");
        }
        yield return text(" ");
        yield return text("« Votre destin est scellé, personne ne pourra vous pardonner, mais je vais vous r" +
            "écompenser pour ce que j\'ai vu. Et je m\'en rappellerai. »");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("C\'est à ce moment que j\'ai dû faire un choix auquel je ne m\'attendais pas et qui " +
            "m\'a hanté pendant tout le trajet en rentrant. Cette générosité condescendante me" +
            " vexait profondément, mais ses mots résonnaient dans ma tête.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Étais-je vraiment devenu un monstre ? ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text("avait peut-être raison ? Et si j\'en avais toujours été un ?");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour revenir...", passage290_Fragment_1);
        using (styleScope("hook", "h000029001"))
            yield return link("Cliquez pour revenir...", null, () => enchantHook("h000029001", HarloweEnchantCommand.Replace, passage290_Fragment_0));

        yield break;
    }

