    {
        using (styleScope("bold", true))
        {
            yield return text("Une visite des plus malvenues");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Note manuscrite - Rédigée par ");
            yield return text(Vars.nameB);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("undated.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("J\'écris ces quelques mots à la lueur de la bougie, car je me suis enfermé derrièr" +
            "e l\'écoinçon sous l\'escalier du premier étage.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Je ne sais pas comment ils ont pu déjouer mes systèmes de défenses mais ces hommes à la peau pâle et aux vêtements noirs et anguleux sont venus jusqu'à ma porte pour me réclamer le paiement d'une ancienne dette. Lorsque mon assistant leur a interdit d'entrer, ils ont purement et simplement dégondé la double porte sans même user d'une arme ou d'un outil. Ils sont encore en train de rôder dans le manoir, en appelant mon nom et en feulant comme des chats de gouttière qui défendent leur repas.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Ils viennent d\'annoncer leurs intentions. Le prix a diablement augmenté ! Ils veu" +
            "lent que je paie ");
        yield return text(Vars.Bcont);
        yield return text("$ immédiatement ou ils me ");
        using (styleScope("bold", true))
        {
            yield return text("TUENT");
        }
        yield return text(". Bon sang, j\'entends leurs pas juste derrière la paroi !");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Choisissez :");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h00304"))
            yield return link("Oui, je vais payer l\'intégralité du montant sur-le-champ.", null, () => enchantHook("h00304", HarloweEnchantCommand.Replace, passage316_Fragment_0));
        yield return lineBreak();
        yield return link("Non, je ne paierai pas. Plutôt mourir !", "Payment2NoB", null);
        yield return text(" <i>(Vous devez choisir cette option si vou" +
            "s ne disposez pas du montant nécessaire. Remettez immédiatement votre Avatar dan" +
            "s la boite.)</i>");
        yield return lineBreak();
        yield break;
    }

