    IStoryThread passage350_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("J\'ACCUSE !");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Tous les joueurs doivent maintenant désigner le joueur qu\'ils croient être à la s" +
            "ource de la malédiction qui frappe la bourgade. Le joueur qui reçoit le plus de " +
            "votes sera tué. ");
        if (Vars.players <= 3)
        {
            yield return lineBreak();
            yield return lineBreak();
            yield return text("L\'");
            yield return text(Vars.wsuspect);
            yield return text("peut aussi être désigné en pointant du doigt les Chroniques de la Ville. L\'");
            yield return text(Vars.wsuspect);
            yield return text("révélera son vote après celui des joueurs.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le premier joueur compte à rebours de 3 à 0. À 0, chaque joueur doit pointer simu" +
            "ltanément du doigt le joueur qu\'il pense être le sorcier.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Gardez les doigts pointés et ");
        yield return link("cliquez ici...", "Witchres1", null);
        yield return lineBreak();
        yield break;
    }


