    // #352: PEWitch2PlayerA

    void passage352_Init()
    {
        this.Passages[@"PEWitch2PlayerA"] = new StoryPassage(@"PEWitch2PlayerA", new string[] { "revised", "rev2", "Trad-FR", }, passage352_Main);
    }

    IStoryThread passage352_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text(Vars.nameA);
            yield return text(" ");
            yield return text("et son obsession");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal de ");
            yield return text(Vars.nameA);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return passage("date1a");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.nameA == Vars.fate1)
        {
            yield return text(@"Ma soif de renommée ne connait aucune frontière. Je ressens un profond désir de reconnaissance, que mon nom soit connu à travers le monde pour mes remarquables percées scientifiques, qu'elles soient obtenues de manière éthique ou marquées du sceau de l'infamie. Mes pensées narcissiques hantent mes journées et polluent mes nuits !");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage352_Fragment_1);
            using (styleScope("hook", "h000035201"))
                yield return link("Once you are ready. click here to reveal your secret conversation.", null, () => enchantHook("h000035201", HarloweEnchantCommand.Replace, passage352_Fragment_0));

        }
        if (Vars.nameA == Vars.fate2)
        {
            yield return text("Ma soif de connaissance est inextinguible. Chaque soir, j\'étudie d\'anciens manusc" +
            "rits et des textes savants, absorbant chaque mot et chaque formule mathématique " +
            "comme si ce devait être la dernière lecture de ma vie !");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage352_Fragment_3);
            using (styleScope("hook", "h000035203"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000035203", HarloweEnchantCommand.Replace, passage352_Fragment_2));

        }
        if (Vars.nameA == Vars.fate3)
        {
            yield return text(@"J'ai passé des jours et des jours à l'abri dans mon laboratoire secret, comme si mon existence toute entière était uniquement dévouée à l'excellence scientifique. Je me fiche de savoir si cela me rendra fou ! Si mes recherches permettent de faire progresser la Science, quel que soit leur apport, cela en aura valu la peine !");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage352_Fragment_5);
            using (styleScope("hook", "h000035205"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000035205", HarloweEnchantCommand.Replace, passage352_Fragment_4));

        }
        if (Vars.nameA == Vars.fate4)
        {
            yield return text(@"Les habitants de cette ville ne sont que d'aigris ignares, la lie de l'humanité. Comment osent-ils regarder de travers une personnalité qui leur est leur tellement supérieure ? Comment osent-ils interférer dans une œuvre aussi grande et aussi précieuse ? Ils doivent PAYER pour leur insolence !");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage352_Fragment_7);
            using (styleScope("hook", "h000035207"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000035207", HarloweEnchantCommand.Replace, passage352_Fragment_6));

        }
        if (Vars.nameA == Vars.fate5)
        {
            yield return text("Je ne tolérerai aucun comportement inapproprié. Ces paysans devraient, tout autan" +
            "t qu\'un roi, apprendre à se tenir correctement en présence d\'un tel génie. C\'est" +
            " à moi de leur montrer ");
            using (styleScope("bold", true))
            {
                yield return text("à tous");
            }
            yield return text("comment rendre dignement hommage à ceux qui leur sont si supérieurs. Ils ne pourr" +
            "ont plus ignorer bien longtemps ma présence incroyablement inspirante et j\'impos" +
            "erai naturellement le respect !");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage352_Fragment_9);
            using (styleScope("hook", "h000035209"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000035209", HarloweEnchantCommand.Replace, passage352_Fragment_8));

        }
        if (Vars.nameA == Vars.fate6)
        {
            yield return text(@"Le simple fait de mener des expériences m'emplit de plaisir. Chaque essai est une véritable délectation que je savoure sans retenue. Et ne serait-ce pas mon devoir - mon droit - de partager cette merveilleuse sensation avec le monde entier ? Les miséreux méritent bien un peu de gaieté, leur vie serait sans doute bien triste sans lumière et sans attention.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage352_Fragment_11);
            using (styleScope("hook", "h0000352011"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h0000352011", HarloweEnchantCommand.Replace, passage352_Fragment_10));

        }
        //yield return link("Cliquez pour continuer...", "PEWitch2PlayerB", null);
        yield break;
    }

