            yield return text(@"Les habitants de cette ville ne sont que d'aigris ignares, la lie de l'humanité. Comment osent-ils regarder de travers une personnalité qui leur est leur tellement supérieure ? Comment osent-ils interférer dans une œuvre aussi grande et aussi précieuse ? Ils doivent PAYER pour leur insolence !");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage356_Fragment_7);
            using (styleScope("hook", "h000035607"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000035607", HarloweEnchantCommand.Replace, passage356_Fragment_6));

        }
        if (Vars.nameE == Vars.fate5)
        {
            yield return text("Je ne tolérerai aucun comportement inapproprié. Ces paysans devraient, tout autan" +
            "t qu\'un roi, apprendre à se tenir correctement en la présence d\'un tel génie. C\'" +
            "est à moi de leur montrer ");
            using (styleScope("bold", true))
            {
                yield return text("à tous");
            }
            yield return text("comment rendre dignement hommage à ceux qui leur sont si supérieurs. Ils ne pourr" +
            "ont plus ignorer bien longtemps ma présence incroyablement inspirante et j\'impos" +
            "erai naturellement le respect !");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage356_Fragment_9);
            using (styleScope("hook", "h000035609"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000035609", HarloweEnchantCommand.Replace, passage356_Fragment_8));

        }
        if (Vars.nameE == Vars.fate6)
        {
            yield return text(@"Le simple fait de mener des expériences m'emplit de plaisir. Chaque essai est une véritable délectation que je savoure sans retenue. Et ne serait-ce pas mon devoir - mon droit - de partager cette merveilleuse sensation avec le monde entier ? Les miséreux méritent bien un peu de gaieté, leur vie serait sans doute bien triste sans lumière et sans attention.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage356_Fragment_11);
            using (styleScope("hook", "h0000356011"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h0000356011", HarloweEnchantCommand.Replace, passage356_Fragment_10));

        }
        yield return link("Cliquez pour continuer...", "PEExplanation1", null);
        yield return lineBreak();
        yield break;
    }

