    // #358: AsylumTestResults

    void passage358_Init()
    {
        this.Passages[@"AsylumTestResults"] = new StoryPassage(@"AsylumTestResults", new string[] { "revised", "Trad-FR", }, passage358_Main);
    }

    IStoryThread passage358_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Patient ");
            yield return text(Vars.question);
            yield return text(" ");
            yield return text("- Résultats de l\'Évaluation");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Après l\'évaluation mentale globale, une étude du métabolisme basal a été effectué" +
            "e, ");
        yield return text(macros1.either("indiquant des résultats anormalement bas qui pourraient être symptomatiques d\'une" +
            " maladie du système endocrinien et nerveux.", "indiquant des résultats plutôt bas qui accompagnent habituellement une tension ar" +
            "térielle basse et une faiblesse générale.", "n\'indiquant aucun paramètre anormal.", "indiquant une valeur légèrement supérieure à la norme, sans doute liée à l\'alimen" +
            "tation du patient.", "montrant un pourcentage anormalement élevé de dioxyde de carbone, parfois associé" +
            " à un comportement agressif et agité."));
        yield return text(" ");
        yield return lineBreak();
        yield return text("Nous avons également procédé à un examen physique général ");
        yield return text(macros1.either("qui a révélé de légers signes de malnutrition et de déshydratation, et une pigmen" +
            "tation du derme habituellement liée au stress.", "révélant la bonne santé du sujet, dont tous les paramètres restent dans les valeu" +
            "rs normées.", "ne révélant rien d\'inquiétant en dehors de quelques marques de brûlure chimique s" +
            "ur les avant-bras.", "montrant des signes d\'obésité liés à une vie sédentaire courante parmi les classe" +
            "s moyennes supérieures."));
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.test <= 3)
        {
            if (Vars.AsylumTestResultsnextpsg == "" || Vars.AsylumTestResultsnextpsg == 0)
            {
                Vars.AsylumTestResultsnextpsg = macros1.either(1, 2, 3, 4, 5);
            }
            Vars.outcome = Vars.AsylumTestResultsnextpsg;
            //Vars.outcome = macros1.either(1, 2, 3, 4, 5);
            if (Vars.outcome == 1)
            {
                yield return text("En tant que spécialiste avisé, je recommande un suivi du patient ");
                yield return text(Vars.question);
                yield return text("au cours des prochaines années. Ce suivi peut prendre la forme de visites réguliè" +
            "res d\'un médecin à son domicile. Le patient est libre de sortir contre le ");
                using (styleScope("bold", true))
                {
                    yield return text("paiement de la somme de : 1$");
                }
                yield return text(".");
                yield return lineBreak();
                yield return lineBreak();
                //yield return enchantIntoLink("Cliquez pour revenir...", passage358_Fragment_1);
                using (styleScope("hook", "h000035801"))
                    yield return link("Cliquez pour revenir...", null, () => enchantHook("h000035801", HarloweEnchantCommand.Replace, passage358_Fragment_0));

            }
            if (Vars.outcome == 2)
            {
                yield return text("Le patient ");
                yield return text(Vars.question);
                yield return text(@"a été admis pour suivre une thérapie électrostatique. Celle-ci se déroule normalement et nous pouvons programmer sa sortie dans les semaines qui viennent. Prescription de laudanum et de phosphates en cas de crise de nerfs. Repos et sédation légère pour assurer le sommeil. Le patient est très contrarié par le repos et l'inaction prescrits.");
                yield return lineBreak();
                yield return lineBreak();
                //yield return enchantIntoLink("Cliquez pour revenir...", passage358_Fragment_3);
                using (styleScope("hook", "h000035803"))
                    yield return link("Cliquez pour revenir...", null, () => enchantHook("h000035803", HarloweEnchantCommand.Replace, passage358_Fragment_2));

            }
            if (Vars.outcome == 3)
            {
                yield return text("J\'ai proposé à un assistant du patient ");
                yield return text(Vars.question);
                yield return text(@"de le former afin qu'il puisse lui prodiguer des soins à domicile à sa sortie. Le comportement et l'état mental du sujet sont suffisamment erratiques pour justifier une surveillance permanente. Bien que le visage de cet assistant laisse supposer qu'il pourrait également avoir besoin d'une psychanalyse, il semble totalement dévoué à ");
                yield return text(Vars.question);
                yield return text("et promet d\'en prendre le plus grand soin.");
                yield return lineBreak();
                yield return lineBreak();
                //yield return enchantIntoLink("Cliquez pour revenir...", passage358_Fragment_5);
                using (styleScope("hook", "h000035805"))
                    yield return link("Cliquez pour revenir...", null, () => enchantHook("h000035805", HarloweEnchantCommand.Replace, passage358_Fragment_4));

            }
            if (Vars.outcome == 4)
            {
                yield return text("Après plusieurs crises soudaines de violence dans nos locaux, nous avons pris la " +
            "décision d\'attacher le sujet ");
                yield return text(Vars.question);
                yield return text(@"chaque soir afin d'éviter qu'il ne se blesse lui-même. J'ai consulté des collègues de la Société Psychanalytique de Vienne et leur analyse indique une répression sexuelle profonde se manifestant par un comportement dissociatif. Nous envisageons de procéder à une stérilisation du sujet qui devrait réduire les tendances violentes envers les autres et sa propre personne.");
                yield return lineBreak();
                yield return lineBreak();
                //yield return enchantIntoLink("Cliquez pour revenir...", passage358_Fragment_7);
                using (styleScope("hook", "h000035807"))
                    yield return link("Cliquez pour revenir...", null, () => enchantHook("h000035807", HarloweEnchantCommand.Replace, passage358_Fragment_6));

            }
            if (Vars.outcome == 5)
            {
                yield return text("Les différents examens révèlent que le patient ");
                yield return text(Vars.question);
                yield return text(@"ne souffre d'aucune déficience physique ou mentale, bien que son comportement soit parfois particulièrement vigoureux. La supposée maladie psychologique a sans doute été provoquée par une montée de stress suite aux récents événements. Je prescris un traitement à base d'héroïne, facilement disponible à un prix raisonnable et sans risque d'addiction. Ses effets relaxants devrait lui permettre de se reposer.");
                yield return lineBreak();
                yield return lineBreak();
                //yield return enchantIntoLink("Cliquez pour revenir...", passage358_Fragment_9);
                using (styleScope("hook", "h000035809"))
                    yield return link("Cliquez pour revenir...", null, () => enchantHook("h000035809", HarloweEnchantCommand.Replace, passage358_Fragment_8));

            }
        }
        else
        {
            yield return text("Le patient ");
            yield return text(Vars.question);
            yield return text(@"a admis au Refuge de manière permanente et illimitée. Je suis persuadé qu'une sortie, même temporaire, d'un sujet souffrant de tendances psychotiques aussi marquées pourrait être dangereuse pour tout le monde. Dieu m'en soit témoin, je ne vois aucune issue positive à un tel désordre mental. En toute conscience, retenir cette personne contre son gré pour l'empêcher de mettre en œuvre sa funeste destinée est la seule chose à faire. ");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour revenir...", passage358_Fragment_11);
            using (styleScope("hook", "h0000358011"))
                yield return link("Cliquez pour revenir...", null, () => enchantHook("h0000358011", HarloweEnchantCommand.Replace, passage358_Fragment_10));

        }
        yield return lineBreak();
        yield return lineBreak();
        //if (Vars.round == 19)
        //{
        //    yield return link("Cliquez pour revenir...", "Liberal", null);
        //}
        //if (Vars.round == 20)
        //{
        //    yield return link("Cliquez pour revenir...", "Liberal2", null);
        //}
        //if (Vars.round == 21)
        //{
        //    yield return link("Cliquez pour revenir...", "Liberal3", null);
        //}
        yield return lineBreak();
        yield break;
    }

