    void passage359_Init()
    {
        this.Passages[@"CountQuestion1"] = new StoryPassage(@"CountQuestion1", new string[] { "revised", "Trad-FR", }, passage359_Main);
    }

    IStoryThread passage359_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Quel est votre groupe sanguin ?");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h00318"))
            yield return link(" I ", null, () => enchantHook("h00318", HarloweEnchantCommand.Replace, passage359_Fragment_0));
        yield return lineBreak();
        using (styleScope("hook", "h00319"))
            yield return link(" II ", null, () => enchantHook("h00319", HarloweEnchantCommand.Replace, passage359_Fragment_1));
